static class DP
{
    static readonly PrivateFontCollection _pfc = Load();

    static PrivateFontCollection Load()
    {
        var pfc = new PrivateFontCollection();
        byte[] data = Convert.FromBase64String(B64Font);
        var h = GCHandle.Alloc(data, GCHandleType.Pinned);
        try { pfc.AddMemoryFont(h.AddrOfPinnedObject(), data.Length); }
        finally { h.Free(); }
        return pfc;
    }

    static FontFamily? _family;
    static FontFamily Family => _family ??= ResolveFamily();
    static FontFamily ResolveFamily()
    {
        foreach (var n in new[] { "Segoe UI Variable Text", "Segoe UI Variable", "Segoe UI" })
            try { var f = new FontFamily(n); if (f.IsStyleAvailable(FontStyle.Regular)) return f; } catch { }
        return _pfc.Families.Length > 0 ? _pfc.Families[0] : SystemFonts.DefaultFont.FontFamily;
    }

    static readonly Dictionary<(float, FontStyle), Font> _cache = new();
    public static Font F(float sz, FontStyle st = FontStyle.Regular)
    {
        var key = (sz, st);
        if (!_cache.TryGetValue(key, out var f))
            _cache[key] = f = new Font(Family, sz, st);
        return f;
    }

    const string B64Font = "";
}

static class Program
{
    internal static readonly string LogFile = Path.Combine(
        Environment.GetFolderPath(Environment.SpecialFolder.UserProfile), "atlas_crash.log");

    static void Log(string msg) {
        try { File.AppendAllText(LogFile, $"[{DateTime.Now:HH:mm:ss}] {msg}\n"); } catch { }
    }

    [STAThread]
    static void Main()
    {
        File.WriteAllText(LogFile, $"--- session {DateTime.Now} ---\n");
        try
        {
            Application.EnableVisualStyles();
            Application.SetCompatibleTextRenderingDefault(false);
            Application.SetUnhandledExceptionMode(UnhandledExceptionMode.CatchException);
            Application.ThreadException += (_, e) => {
                Log("thread ex: " + e.Exception);
                MessageBox.Show(e.Exception.Message, "Atlas error");
            };
            AppDomain.CurrentDomain.UnhandledException += (_, e) => Log("unhandled: " + e.ExceptionObject);
            Log("ok");
            Application.Run(new MainForm());
        }
        catch (Exception ex)
        {
            Log("fatal: " + ex);
            MessageBox.Show(ex.ToString(), "Fatal error");
        }
    }
}

public class AtlasConfig
{

    [JsonPropertyName("monitor")]    public int     MonitorIdx  { get; set; } = 0;
    [JsonPropertyName("resolution")] public string  Res         { get; set; } = "1080p";
    [JsonPropertyName("fps")]        public int     Fps         { get; set; } = 30;
    [JsonPropertyName("audio_name")] public string? AudioDevice { get; set; }
    [JsonPropertyName("mic_name")]   public string? MicDevice   { get; set; }
    [JsonPropertyName("duration")]   public string  ClipLen     { get; set; } = "30 sec";
    [JsonPropertyName("hotkey")]     public string  Hotkey      { get; set; } = "f9";
    [JsonPropertyName("output_dir")] public string  OutDir      { get; set; } =
        Path.Combine(Environment.GetFolderPath(Environment.SpecialFolder.UserProfile), "clips");
    [JsonPropertyName("topmost")]    public bool    Topmost     { get; set; } = false;
    [JsonPropertyName("sidebar")]        public bool    SidebarMode    { get; set; } = false;
    [JsonPropertyName("hotkey_on")]      public bool    HotkeyOn       { get; set; } = true;
    [JsonPropertyName("sidebar_hotkey")] public string  SidebarHotkey  { get; set; } = "";
    [JsonPropertyName("format")]         public string  Format      { get; set; } = "mp4";
    [JsonPropertyName("cursor")]         public bool    ShowCursor  { get; set; } = true;
    [JsonPropertyName("filename_tpl")]   public string  FilenameTpl  { get; set; } = "clip_{yyyyMMdd}_{HHmmss}";
    [JsonPropertyName("hotkey_alt")]     public string  HotkeyAlt    { get; set; } = "";
    [JsonPropertyName("clip_len_alt")]   public string  ClipLenAlt   { get; set; } = "1 min";
    [JsonPropertyName("mic_hk")]         public string  MicHotkey    { get; set; } = "";
    [JsonPropertyName("crf")]            public int     Crf          { get; set; } = 23;
    [JsonPropertyName("max_ram_mb")]     public int     MaxRamMb     { get; set; } = 512;

    static string SettingsPath => Path.Combine(
        Environment.GetFolderPath(Environment.SpecialFolder.UserProfile), ".atlas.json");

    public static AtlasConfig Load()
    {
        if (!File.Exists(SettingsPath)) return new();
        try {
            return JsonSerializer.Deserialize<AtlasConfig>(File.ReadAllText(SettingsPath), _loadOpts) ?? new();
        }
        catch (JsonException) {

            try { File.Delete(SettingsPath); } catch { }
            return new();
        }
    }

    static readonly JsonSerializerOptions _jsonOpts = new() { WriteIndented = true };
    static readonly JsonSerializerOptions _loadOpts = new() { PropertyNameCaseInsensitive = true };

    public void Persist()
    {
        try {
            File.WriteAllText(SettingsPath, JsonSerializer.Serialize(this, _jsonOpts));
        } catch (UnauthorizedAccessException) { }
    }
}

public class RingBuffer<T>
{
    readonly Queue<(double when, T payload)> items = new();
    readonly Func<T, long>? sizer;
    readonly Action<T>? _onEvict;
    readonly object gate = new();
    double keepSecs = 65;
    long _totalBytes;
    long _maxBytes;

    public RingBuffer(Func<T, long>? sizer = null, long maxBytes = 0, Action<T>? onEvict = null)
    { this.sizer = sizer; _maxBytes = maxBytes; _onEvict = onEvict; }
    public void SetMaxBytes(long maxBytes) { lock (gate) _maxBytes = maxBytes; }

    public double WindowSecs { set { lock (gate) keepSecs = value; } }

    void Evict(T payload)
    {
        if (sizer != null) _totalBytes -= sizer(payload);
        _onEvict?.Invoke(payload);
    }

    public void Add(double ts, T item)
    {
        lock (gate)
        {
            items.Enqueue((ts, item));
            if (sizer != null) _totalBytes += sizer(item);
            double oldest = ts - keepSecs;
            while (items.Count > 0 && items.Peek().when < oldest)
                Evict(items.Dequeue().payload);
            if (_maxBytes > 0 && sizer != null)
                while (items.Count > 1 && _totalBytes > _maxBytes)
                    Evict(items.Dequeue().payload);
        }
    }

    public List<(double when, T payload)> Since(double cutoff)
    {
        lock (gate)
        {
            var result = new List<(double, T)>(items.Count);
            foreach (var item in items)
                if (item.when >= cutoff) result.Add(item);
            return result;
        }
    }

    public int  ApproxCount { get { lock (gate) return items.Count; } }
    public long ApproxBytes { get { lock (gate) return _totalBytes; } }
    public void Clear()
    {
        lock (gate) {
            if (_onEvict != null)
                foreach (var item in items) _onEvict(item.payload);
            items.Clear(); _totalBytes = 0;
        }
    }
}

static class FfmpegFinder
{
    static readonly string CacheDir  = Path.Combine(Environment.GetFolderPath(Environment.SpecialFolder.LocalApplicationData), "Atlas");
    static readonly string CachePath = Path.Combine(CacheDir, "ffmpeg.exe");

    public static string? Locate()
    {

        var next2exe = Path.Combine(AppContext.BaseDirectory, "ffmpeg.exe");
        if (File.Exists(next2exe)) return next2exe;

        if (File.Exists(CachePath)) return CachePath;

        var stream = System.Reflection.Assembly.GetExecutingAssembly()
            .GetManifestResourceStream("Atlas.ffmpeg.exe");
        if (stream != null)
        {
            try
            {
                Directory.CreateDirectory(CacheDir);
                using var fs = File.Create(CachePath);
                stream.CopyTo(fs);
                return CachePath;
            }
            catch { }
        }

        foreach (var dir in (Environment.GetEnvironmentVariable("PATH") ?? "").Split(';').Where(d => !string.IsNullOrWhiteSpace(d)))
        {
            var p = Path.Combine(dir.Trim(), "ffmpeg.exe");
            if (File.Exists(p)) return p;
        }
        return null;
    }
}

static class GameDetector
{
    [DllImport("user32.dll")] static extern IntPtr GetForegroundWindow();
    [DllImport("user32.dll")] static extern uint   GetWindowThreadProcessId(IntPtr hwnd, out uint pid);

    static readonly Dictionary<string, string> _known = new(StringComparer.OrdinalIgnoreCase) {
        ["RobloxPlayerBeta"]                  = "Roblox",
        ["RobloxPlayer"]                      = "Roblox",
        ["vrchat"]                            = "VRChat",
        ["Minecraft.Windows"]                 = "Minecraft",
        ["javaw"]                             = "Minecraft",
        ["GTA5"]                              = "GTA_V",
        ["FortniteClient-Win64-Shipping"]     = "Fortnite",
        ["RocketLeague"]                      = "Rocket_League",
        ["csgo"]                              = "CS_GO",
        ["cs2"]                               = "CS2",
        ["r5apex"]                            = "Apex_Legends",
        ["VALORANT-Win64-Shipping"]           = "Valorant",
        ["Cyberpunk2077"]                     = "Cyberpunk_2077",
        ["witcher3"]                          = "The_Witcher_3",
        ["eldenring"]                         = "Elden_Ring",
        ["LeagueOfLegends"]                   = "League_of_Legends",
        ["EscapeFromTarkov"]                  = "Tarkov",
        ["DayZ_x64"]                          = "DayZ",
        ["rust"]                              = "Rust",
        ["Phasmophobia"]                      = "Phasmophobia",
        ["RainbowSix"]                        = "Rainbow_Six_Siege",
        ["HaloInfinite"]                      = "Halo_Infinite",
        ["destiny2"]                          = "Destiny_2",
        ["WorldOfWarcraft"]                   = "WoW",
        ["ffxiv_dx11"]                        = "FFXIV",
        ["GenshinImpact"]                     = "Genshin_Impact",
        ["overwatch"]                         = "Overwatch_2",
        ["Overwatch"]                         = "Overwatch_2",
        ["Among Us"]                          = "Among_Us",
        ["Terraria"]                          = "Terraria",
        ["Stardew Valley"]                    = "Stardew_Valley",
        ["cod"]                               = "Call_of_Duty",
        ["ModernWarfare"]                     = "MW",
        ["BlackOps6"]                         = "BO6",
    };

    static readonly char[]          _invalidFileChars = Path.GetInvalidFileNameChars();
    static readonly char[]          _titleSeps        = ['|', '-', '—', '·', ':'];
    static readonly HashSet<string> _skip = new(StringComparer.OrdinalIgnoreCase) {
        "explorer","chrome","firefox","msedge","opera","brave","iexplore",
        "discord","slack","teams","zoom","skype","telegram","whatsapp",
        "obs64","obs32","streamlabsobs","nvcontainer","nvsphelper64",
        "taskmgr","notepad","code","devenv","rider",
        "Atlas","Clipper","SearchHost","StartMenuExperienceHost",
        "ShellExperienceHost","RuntimeBroker","svchost","dwm","winlogon",
        "spotify","steam","steamwebhelper","epicgameslauncher","battle.net",
    };

    public static string Detect()
    {
        // Priority: foreground window at clip time (almost always the game)
        try {
            GetWindowThreadProcessId(GetForegroundWindow(), out uint pid);
            using var proc = Process.GetProcessById((int)pid);
            string? name = Resolve(proc);
            if (name != null) return name;
        } catch { }

        // Fallback: scan for any known game process
        var all = Process.GetProcesses();
        string? found = null;
        try {
            foreach (var p in all) {
                try { if (_known.TryGetValue(p.ProcessName, out string? n) && n != null) { found = n; break; } }
                catch { }
            }
        } finally { foreach (var p in all) try { p.Dispose(); } catch { } }

        return found ?? "clip";
    }

    static string? Resolve(Process proc)
    {
        if (_skip.Contains(proc.ProcessName)) return null;
        if (_known.TryGetValue(proc.ProcessName, out string? mapped)) return mapped;

        // Use window title — take the first segment before a separator
        string title = "";
        try { title = proc.MainWindowTitle; } catch { }
        if (title.Length > 1) {
            foreach (char sep in _titleSeps) {
                int idx = title.IndexOf(sep);
                if (idx > 1) { title = title[..idx]; break; }
            }
            title = title.Trim();
            if (title.Length > 0) return Sanitize(title);
        }
        return null;
    }

    static string Sanitize(string s)
    {
        var sb = new System.Text.StringBuilder(s.Length);
        foreach (char c in s) sb.Append(_invalidFileChars.Contains(c) || c == ' ' ? '_' : c);
        return sb.ToString().Trim('_');
    }
}

public record DisplayInfo(Rectangle Rect, string Label)
{
    public override string ToString() => $"{Label}  ({Rect.Width}×{Rect.Height})";
}

static class DisplayHelper
{
    public static List<DisplayInfo> Enumerate()
    {
        var screens = Screen.AllScreens;
        var names   = TryReadEdidNames();
        return screens.Select((s, i) => {
            var name = i < names.Count && !string.IsNullOrEmpty(names[i]) ? names[i] : $"Display {i + 1}";
            return new DisplayInfo(s.Bounds, name);
        }).ToList();
    }

    static List<string> TryReadEdidNames()
    {
        var result = new List<string>();
        try
        {
            var dd = new DISPLAY_DEVICE { cb = Marshal.SizeOf<DISPLAY_DEVICE>() };
            for (uint i = 0; EnumDisplayDevices(null, i, ref dd, 0); i++)
            {
                if ((dd.StateFlags & 1) != 0)
                {
                    var mon = new DISPLAY_DEVICE { cb = Marshal.SizeOf<DISPLAY_DEVICE>() };
                    EnumDisplayDevices(dd.DeviceName, 0, ref mon, 1);
                    result.Add(ParseEdidMonitorName(mon.DeviceID) ?? "");
                }
                dd = new DISPLAY_DEVICE { cb = Marshal.SizeOf<DISPLAY_DEVICE>() };
            }
        }
        catch {  }
        return result;
    }

    static readonly System.Text.RegularExpressions.Regex _edidRx =
        new(@"DISPLAY#([^#]+)#", System.Text.RegularExpressions.RegexOptions.Compiled);

    static string? ParseEdidMonitorName(string deviceId)
    {
        try
        {
            var match = _edidRx.Match(deviceId);
            if (!match.Success) return null;

            using var key = Registry.LocalMachine.OpenSubKey(
                $@"SYSTEM\CurrentControlSet\Enum\DISPLAY\{match.Groups[1].Value}");
            if (key == null) return null;

            foreach (var sub in key.GetSubKeyNames())
            {
                using var pk = key.OpenSubKey($@"{sub}\Device Parameters");
                if (pk?.GetValue("EDID") is not byte[] edid) continue;

                for (int j = 0; j < 4; j++)
                {
                    int o = 54 + j * 18;
                    if (edid.Length < o + 18) break;
                    if (edid[o+3] == 0xFC)
                        return System.Text.Encoding.ASCII.GetString(edid, o + 5, 13).TrimEnd('\n', ' ');
                }
            }
        }
        catch (Exception) { }
        return null;
    }

    [StructLayout(LayoutKind.Sequential, CharSet = CharSet.Unicode)]
    struct DISPLAY_DEVICE
    {
        public int cb;
        [MarshalAs(UnmanagedType.ByValTStr, SizeConst = 32)]  public string DeviceName;
        [MarshalAs(UnmanagedType.ByValTStr, SizeConst = 128)] public string DeviceString;
        public uint StateFlags;
        [MarshalAs(UnmanagedType.ByValTStr, SizeConst = 128)] public string DeviceID;
        [MarshalAs(UnmanagedType.ByValTStr, SizeConst = 128)] public string DeviceKey;
    }

    [DllImport("user32.dll", CharSet = CharSet.Unicode)]
    static extern bool EnumDisplayDevices(string? lpDevice, uint iDevNum, ref DISPLAY_DEVICE lpDD, uint dwFlags);
}

public static class Theme
{
    public static readonly Color Base         = Color.FromArgb(0x0B, 0x0C, 0x0F);
    public static readonly Color Surface      = Color.FromArgb(0x15, 0x17, 0x1C);
    public static readonly Color SurfaceRaise = Color.FromArgb(0x1C, 0x1F, 0x26);
    public static readonly Color SurfaceSunk  = Color.FromArgb(0x0E, 0x10, 0x14);
    public static readonly Color Border       = Color.FromArgb(0x26, 0x2A, 0x33);
    public static readonly Color BorderSubtle = Color.FromArgb(0x1B, 0x1E, 0x25);
    public static readonly Color TextPrimary   = Color.FromArgb(0xF2, 0xF4, 0xF8);
    public static readonly Color TextSecondary = Color.FromArgb(0x9B, 0xA3, 0xB0);
    public static readonly Color TextTertiary  = Color.FromArgb(0x5C, 0x64, 0x70);
    public static readonly Color Accent        = Color.FromArgb(0x3B, 0x82, 0xF6);
    public static readonly Color AccentHover   = Color.FromArgb(0x4F, 0x90, 0xFF);
    public static readonly Color AccentPressed = Color.FromArgb(0x2E, 0x6F, 0xD6);
    public static readonly Color AccentTint    = Color.FromArgb(0x60, 0xA5, 0xFA);
    public static readonly Color Danger        = Color.FromArgb(0xF8, 0x51, 0x49);
    public const int RadiusSm = 6, RadiusMd = 9;

    public static Color Lerp(Color a, Color b, float t)
    {
        float s = 1f - t;
        return Color.FromArgb(
            (int)(a.A * s + b.A * t), (int)(a.R * s + b.R * t),
            (int)(a.G * s + b.G * t), (int)(a.B * s + b.B * t));
    }

    public static GraphicsPath RoundRect(Rectangle r, int radius)
    {
        int d = radius * 2;
        var p = new GraphicsPath();
        p.AddArc(r.X,         r.Y,          d, d, 180, 90);
        p.AddArc(r.Right - d, r.Y,          d, d, 270, 90);
        p.AddArc(r.Right - d, r.Bottom - d, d, d,   0, 90);
        p.AddArc(r.X,         r.Bottom - d, d, d,  90, 90);
        p.CloseFigure();
        return p;
    }
}

static class DwmHelper
{
    [DllImport("dwmapi.dll")] static extern int DwmSetWindowAttribute(IntPtr hwnd, int attr, ref int val, int size);
    public static void Apply(IntPtr hwnd)
    {
        TrySet(hwnd, 20, 1);  // dark mode
        TrySet(hwnd, 33, 2);  // rounded corners (Win11)
        TrySet(hwnd, 38, 2);  // Mica backdrop (Win11 22H2+)
    }
    static void TrySet(IntPtr hwnd, int attr, int val)
    { try { DwmSetWindowAttribute(hwnd, attr, ref val, sizeof(int)); } catch { } }
}

public class ThinBar : Control
{
    double cur, cap = 1;
    static readonly SolidBrush _brEmpty  = new(Theme.Border);
    static readonly SolidBrush _brFilled = new(Theme.Accent);

    public ThinBar() { DoubleBuffered = true; Height = 4; }

    public void SetProgress(double value, double maximum)
    {
        cur = value; cap = maximum > 0 ? maximum : 1;
        Invalidate();
    }

    protected override void OnPaint(PaintEventArgs e)
    {
        var g = e.Graphics;
        g.SmoothingMode = SmoothingMode.AntiAlias;
        using var pathBg = RoundRect(new Rectangle(0, 0, Width, Height), 2);
        g.FillPath(_brEmpty, pathBg);
        if (cur > 0) {
            int px = Math.Max(4, (int)(Width * cur / cap));
            using var pathFg = RoundRect(new Rectangle(0, 0, px, Height), 2);
            g.FillPath(_brFilled, pathFg);
        }
    }

    static GraphicsPath RoundRect(Rectangle r, int radius)
    {
        int d = radius * 2;
        var p = new GraphicsPath();
        p.AddArc(r.X, r.Y, d, d, 180, 90);
        p.AddArc(r.Right - d, r.Y, d, d, 270, 90);
        p.AddArc(r.Right - d, r.Bottom - d, d, d, 0, 90);
        p.AddArc(r.X, r.Bottom - d, d, d, 90, 90);
        p.CloseFigure();
        return p;
    }
}

sealed class VuMeter : Control
{
    volatile float _level;
    static readonly SolidBrush _brBg   = new(Color.FromArgb(0x16, 0x16, 0x16));
    static readonly SolidBrush _brFill = new(Color.FromArgb(0x22, 0xD3, 0xEE));
    static readonly SolidBrush _brClip = new(Color.FromArgb(0xF0, 0x45, 0x45));

    public VuMeter() { Height = 4; DoubleBuffered = true; }

    public void SetLevel(float level)
    {
        float clamped = Math.Clamp(level, 0f, 1f);
        if (Math.Abs(clamped - _level) > 0.01f) { _level = clamped; Invalidate(); }
    }

    protected override void OnPaint(PaintEventArgs e)
    {
        e.Graphics.FillRectangle(_brBg, 0, 0, Width, Height);
        if (_level > 0)
        {
            int px = (int)(Width * _level);
            e.Graphics.FillRectangle(_level > 0.9f ? _brClip : _brFill, 0, 0, px, Height);
        }
    }
}

sealed class ClipToast : Form
{
    static readonly Font _font = DP.F(11f);
    static readonly SolidBrush _brBg   = new(Color.FromArgb(220, 0x18, 0x18, 0x18));
    static readonly SolidBrush _brText = new(Color.FromArgb(0xE8, 0xE8, 0xE8));
    static readonly SolidBrush _brDot  = new(Color.FromArgb(0x3B, 0x82, 0xF6));
    System.Windows.Forms.Timer? _fade;

    public ClipToast(Rectangle monitorRect)
    {
        FormBorderStyle = FormBorderStyle.None;
        ShowInTaskbar   = false;
        TopMost         = true;
        BackColor       = Color.FromArgb(0x18, 0x18, 0x18);
        TransparencyKey = Color.Magenta;
        Size = new Size(160, 34);
        var wa = Screen.FromRectangle(monitorRect).WorkingArea;
        Location = new Point(wa.Right - Width - 16, wa.Top + 16);
        SetStyle(ControlStyles.UserPaint | ControlStyles.OptimizedDoubleBuffer | ControlStyles.AllPaintingInWmPaint, true);
        Opacity = 0.92;
    }

    public void ShowToast()
    {
        Show();
        _fade = new System.Windows.Forms.Timer { Interval = 40 };
        _fade.Tick += (_, _) => {
            Opacity -= 0.045;
            if (Opacity <= 0) { _fade.Stop(); _fade.Dispose(); Close(); Dispose(); }
        };
        var hold = new System.Windows.Forms.Timer { Interval = 1400 };
        hold.Tick += (_, _) => { hold.Stop(); hold.Dispose(); _fade.Start(); };
        hold.Start();
    }

    protected override void OnPaint(PaintEventArgs e)
    {
        var g = e.Graphics;
        g.SmoothingMode = SmoothingMode.AntiAlias;
        g.TextRenderingHint = System.Drawing.Text.TextRenderingHint.ClearTypeGridFit;
        g.Clear(Color.FromArgb(0x18, 0x18, 0x18));
        g.FillEllipse(_brDot, 10, Height / 2 - 5, 10, 10);
        g.DrawString("Saving clip…", _font, _brText, new RectangleF(26, 0, Width - 30, Height),
            new StringFormat { LineAlignment = StringAlignment.Center });
    }

    protected override bool ShowWithoutActivation => true;
    protected override CreateParams CreateParams {
        get { var cp = base.CreateParams; cp.ExStyle |= 0x80; return cp; }
    }
}

public class RoundButton : Control
{
    enum Variant { Secondary, Primary, Danger }

    readonly Action _onClick;
    readonly Variant _variant;
    bool _hovering, _pressing;
    float _hoverT, _animTarget;
    System.Windows.Forms.Timer? _animTimer;

    public RoundButton(string label, Action action, int w, int h = 30, bool green = false, bool danger = false)
    {
        _onClick = action;
        _variant = danger ? Variant.Danger : green ? Variant.Primary : Variant.Secondary;
        Text     = label;
        Size     = new Size(w, h);
        Font     = DP.F(10f, FontStyle.Bold);
        Cursor   = Cursors.Hand;
        SetStyle(ControlStyles.AllPaintingInWmPaint | ControlStyles.UserPaint |
                 ControlStyles.OptimizedDoubleBuffer | ControlStyles.ResizeRedraw, true);
    }

    void StartAnim(float target)
    {
        _animTarget = target;
        if (_animTimer == null)
        {
            _animTimer = new System.Windows.Forms.Timer { Interval = 14 };
            _animTimer.Tick += OnAnimTick;
        }
        _animTimer.Start();
    }

    void OnAnimTick(object? s, EventArgs e)
    {
        float step = 0.15f;
        if (Math.Abs(_hoverT - _animTarget) <= step) { _hoverT = _animTarget; _animTimer?.Stop(); }
        else _hoverT += _animTarget > _hoverT ? step : -step;
        Invalidate();
    }

    protected override void OnMouseEnter(EventArgs e) { _hovering = true;  StartAnim(1f); base.OnMouseEnter(e); }
    protected override void OnMouseLeave(EventArgs e) { _hovering = _pressing = false; StartAnim(0f); base.OnMouseLeave(e); }
    protected override void OnMouseDown(MouseEventArgs e) { if (e.Button == MouseButtons.Left) { _pressing = true; Invalidate(); } base.OnMouseDown(e); }
    protected override void OnMouseUp(MouseEventArgs e) { _pressing = false; Invalidate(); base.OnMouseUp(e); }
    protected override void OnEnabledChanged(EventArgs e) { Invalidate(); base.OnEnabledChanged(e); }
    protected override void OnClick(EventArgs e) { if (Enabled) _onClick(); base.OnClick(e); }

    protected override void Dispose(bool disposing)
    {
        if (disposing && _animTimer != null) { _animTimer.Stop(); _animTimer.Tick -= OnAnimTick; _animTimer.Dispose(); }
        base.Dispose(disposing);
    }

    protected override void OnPaint(PaintEventArgs e)
    {
        var g = e.Graphics;
        g.SmoothingMode     = SmoothingMode.AntiAlias;
        g.PixelOffsetMode   = PixelOffsetMode.HighQuality;
        g.TextRenderingHint = TextRenderingHint.ClearTypeGridFit;

        int py = _pressing ? 1 : 0;
        var r  = new Rectangle(0, py, Width - 1, Height - 1 - py);
        using var path = Theme.RoundRect(r, Theme.RadiusSm);
        float t = _hoverT;

        var tfFlags = TextFormatFlags.HorizontalCenter | TextFormatFlags.VerticalCenter | TextFormatFlags.SingleLine;

        if (!Enabled)
        {
            using var brD = new SolidBrush(Theme.SurfaceSunk);
            g.FillPath(brD, path);
            using var penD = new Pen(Theme.BorderSubtle, 1f);
            g.DrawPath(penD, path);
            TextRenderer.DrawText(g, Text, Font, new Rectangle(0, py, Width, Height - py), Theme.TextTertiary, tfFlags);
            return;
        }

        switch (_variant)
        {
            case Variant.Primary:
            {
                Color top = _pressing ? Theme.AccentPressed : Theme.Lerp(Theme.Accent, Theme.AccentHover, t * 0.7f);
                Color bot = _pressing ? Theme.Lerp(Theme.AccentPressed, Color.Black, 0.12f)
                                      : Theme.Lerp(Theme.Lerp(Theme.Accent, Color.Black, 0.09f), Theme.AccentHover, t * 0.5f);
                using var grad = new LinearGradientBrush(new Rectangle(0, 0, 1, Math.Max(1, Height)), top, bot, LinearGradientMode.Vertical);
                g.FillPath(grad, path);
                if (!_pressing)
                {
                    using var penHL = new Pen(Color.FromArgb(48, 255, 255, 255), 1f);
                    g.DrawLine(penHL, r.X + Theme.RadiusSm, r.Y + 1, r.Right - Theme.RadiusSm, r.Y + 1);
                }
                if (t > 0.05f)
                {
                    using var penGlow = new Pen(Color.FromArgb((int)(t * 68), 59, 130, 246), 2f);
                    using var gp2 = Theme.RoundRect(new Rectangle(-1, py - 1, Width + 1, Height + 1 - py), Theme.RadiusSm + 2);
                    g.DrawPath(penGlow, gp2);
                }
                TextRenderer.DrawText(g, Text, Font, new Rectangle(0, py, Width, Height - py),
                    Color.FromArgb(0xF0, 0xF6, 0xFF), tfFlags);
                break;
            }
            case Variant.Danger:
            {
                Color bg  = _pressing ? Color.FromArgb(0x2C, 0x12, 0x12)
                           : Theme.Lerp(Theme.Surface, Color.FromArgb(0x22, 0x10, 0x10), t);
                Color bdr = Theme.Lerp(Theme.Border, Theme.Danger, t * t);
                Color txt = Theme.Lerp(Theme.TextSecondary, Theme.Danger, t);
                using var brBg = new SolidBrush(bg);
                g.FillPath(brBg, path);
                using var penBdr = new Pen(bdr, 1f);
                g.DrawPath(penBdr, path);
                TextRenderer.DrawText(g, Text, Font, new Rectangle(0, py, Width, Height - py), txt, tfFlags);
                break;
            }
            default:
            {
                Color bg  = _pressing ? Theme.SurfaceSunk : Theme.Lerp(Theme.Surface, Theme.SurfaceRaise, t);
                Color bdr = _pressing ? Theme.Accent : Theme.Lerp(Theme.Border, Color.FromArgb(0x44, 0x4C, 0x60), t);
                Color txt = Theme.Lerp(Theme.TextSecondary, Theme.TextPrimary, t);
                using var brBg = new SolidBrush(bg);
                g.FillPath(brBg, path);
                using var penBdr = new Pen(bdr, 1f);
                g.DrawPath(penBdr, path);
                TextRenderer.DrawText(g, Text, Font, new Rectangle(0, py, Width, Height - py), txt, tfFlags);
                break;
            }
        }
    }
}

public class StyledTextBox : Control
{
    readonly TextBox inner;

    static readonly Color bgColor    = Theme.Surface;
    static readonly Color edgeNormal = Theme.Border;
    static readonly Color edgeFocused= Theme.Accent;
    static readonly Color textColor  = Theme.TextPrimary;
    static readonly Pen _penNormal  = new(edgeNormal, 1f);
    static readonly Pen _penFocused = new(edgeFocused, 1.5f);

    public new string Text { get => inner.Text; set => inner.Text = value; }
    public new Font   Font { get => inner.Font; set => inner.Font = value; }
    public new event EventHandler?    TextChanged { add => inner.TextChanged += value; remove => inner.TextChanged -= value; }
    public new event KeyEventHandler? KeyDown     { add => inner.KeyDown    += value; remove => inner.KeyDown    -= value; }
    public new event EventHandler?    Leave       { add => inner.Leave      += value; remove => inner.Leave      -= value; }

    public StyledTextBox(string initial = "")
    {
        BackColor = bgColor;
        inner = new TextBox {
            BorderStyle = BorderStyle.None,
            BackColor   = bgColor,
            ForeColor   = textColor,
            Font        = DP.F(9f),
            Text        = initial,
        };
        inner.GotFocus  += (_, _) => Invalidate();
        inner.LostFocus += (_, _) => Invalidate();
        Controls.Add(inner);
        SetStyle(ControlStyles.UserPaint | ControlStyles.OptimizedDoubleBuffer | ControlStyles.AllPaintingInWmPaint, true);
    }

    public new void Focus() => inner.Focus();

    protected override void OnSizeChanged(EventArgs e)
    {
        base.OnSizeChanged(e);
        inner.SetBounds(8, (Height - inner.PreferredHeight) / 2, Width - 16, inner.PreferredHeight);
    }

    protected override void OnPaint(PaintEventArgs e)
    {
        e.Graphics.Clear(bgColor);
        e.Graphics.DrawRectangle(
            inner.Focused ? _penFocused : _penNormal,
            0, 0, Width - 1, Height - 1);
    }
}

public class HotkeyCapture : Control
{
    bool listening;
    string current;

    static readonly Color bgColor    = Theme.Surface;
    static readonly Color edgeIdle   = Theme.Border;
    static readonly Color edgeFocus  = Theme.Accent;
    static readonly Color edgeListen = Color.FromArgb(0xEA, 0x88, 0x0C);
    static readonly Color textColor  = Theme.TextPrimary;
    static readonly Color hintColor  = Color.FromArgb(0x48, 0x48, 0x48);
    static readonly Pen _penIdle     = new(edgeIdle, 1f);
    static readonly Pen _penFocus    = new(edgeFocus, 1f);
    static readonly Pen _penListen   = new(edgeListen, 1f);
    static readonly SolidBrush _brText = new(textColor);
    static readonly SolidBrush _brHint = new(hintColor);
    static readonly StringFormat _hkSf = new() { LineAlignment = StringAlignment.Center };

    public string Hotkey
    {
        get => current;
        set { current = value; Invalidate(); }
    }

    public event EventHandler? HotkeyChanged;

    public HotkeyCapture(string initial = "")
    {
        current = initial;
        Height  = 54;
        Cursor  = Cursors.Hand;
        Font    = DP.F(14f);
        SetStyle(ControlStyles.UserPaint | ControlStyles.OptimizedDoubleBuffer |
                 ControlStyles.AllPaintingInWmPaint | ControlStyles.Selectable | ControlStyles.ResizeRedraw, true);
        TabStop = true;
    }

    protected override void OnMouseDown(MouseEventArgs e) { if (e.Button == MouseButtons.Left) { Focus(); listening = true; Invalidate(); } base.OnMouseDown(e); }
    protected override void OnGotFocus(EventArgs e)  { Invalidate(); base.OnGotFocus(e); }
    protected override void OnLostFocus(EventArgs e) { listening = false; Invalidate(); base.OnLostFocus(e); }
    protected override bool IsInputKey(Keys k)       => true;

    protected override void OnKeyDown(KeyEventArgs e)
    {
        if (!listening) { base.OnKeyDown(e); return; }
        e.SuppressKeyPress = true;

        if (e.KeyCode is Keys.ControlKey or Keys.LControlKey or Keys.RControlKey
            or Keys.ShiftKey or Keys.LShiftKey or Keys.RShiftKey
            or Keys.Menu or Keys.LMenu or Keys.RMenu
            or Keys.LWin or Keys.RWin)
        { base.OnKeyDown(e); return; }

        if (e.KeyCode == Keys.Escape) { listening = false; Invalidate(); base.OnKeyDown(e); return; }

        var parts = new List<string>();
        if (e.Control) parts.Add("ctrl");
        if (e.Alt)     parts.Add("alt");
        if (e.Shift)   parts.Add("shift");

        string key = e.KeyCode switch {
            >= Keys.F1  and <= Keys.F24 => e.KeyCode.ToString().ToLower(),
            >= Keys.D0  and <= Keys.D9  => ((int)e.KeyCode - (int)Keys.D0).ToString(),
            Keys.Oemtilde    => "`",
            Keys.OemMinus    => "-",
            Keys.Oemplus     => "=",
            Keys.OemOpenBrackets => "[",
            Keys.Oem6        => "]",
            Keys.Oem5        => "\\",
            Keys.OemSemicolon=> ";",
            Keys.OemQuotes   => "'",
            Keys.Oemcomma    => ",",
            Keys.OemPeriod   => ".",
            Keys.OemQuestion => "/",
            Keys.Space       => "space",
            Keys.Insert      => "insert",
            Keys.Delete      => "delete",
            Keys.Home        => "home",
            Keys.End         => "end",
            Keys.Prior       => "pgup",
            Keys.Next        => "pgdn",
            _                => e.KeyCode.ToString().ToLower(),
        };
        parts.Add(key);

        current   = string.Join("+", parts);
        listening = false;
        Invalidate();
        HotkeyChanged?.Invoke(this, EventArgs.Empty);

        base.OnKeyDown(e);
    }

    protected override void OnPaint(PaintEventArgs e)
    {
        var g = e.Graphics;
        g.TextRenderingHint = TextRenderingHint.ClearTypeGridFit;
        g.Clear(bgColor);

        var pen = listening ? _penListen : Focused ? _penFocus : _penIdle;
        g.DrawRectangle(pen, 0, 0, Width - 1, Height - 1);

        if (listening)
            g.DrawString("Press keys…", Font, _brHint,
                new RectangleF(8, 0, Width - 16, Height), _hkSf);
        else
            g.DrawString(current, Font, _brText,
                new RectangleF(8, 0, Width - 16, Height), _hkSf);
    }
}

public class DropPicker : Control
{
    static readonly Color bgOff  = Theme.Surface;
    static readonly Color bgHov  = Theme.SurfaceRaise;
    static readonly Color bgOpen = Theme.SurfaceSunk;
    static readonly Color rimOff = Theme.Border;
    static readonly Color rimOn  = Color.FromArgb(0x3C, 0x44, 0x58);
    static readonly Color itemFg = Theme.TextPrimary;
    static readonly Color arrOff = Theme.TextTertiary;
    static readonly Color arrOn  = Theme.Accent;
    static readonly SolidBrush _brBgOff  = new(bgOff);
    static readonly SolidBrush _brBgHov  = new(bgHov);
    static readonly SolidBrush _brBgOpen = new(bgOpen);
    static readonly SolidBrush _brItemFg = new(itemFg);
    static readonly SolidBrush _brArrOff = new(arrOff);
    static readonly SolidBrush _brArrOn  = new(arrOn);
    static readonly Pen _penRimOff = new(rimOff, 1f);
    static readonly Pen _penRimOn  = new(rimOn, 1f);
    static readonly StringFormat _dpSf = new() {
        LineAlignment = StringAlignment.Center,
        Trimming      = StringTrimming.EllipsisCharacter,
        FormatFlags   = StringFormatFlags.NoWrap,
    };

    readonly List<string> choices = [];
    readonly PointF[] _tri = new PointF[3];
    int  selectedIdx = -1;
    bool mouseOver, blockClick;
    FlyoutList? flyout;

    public int SelectedIndex
    {
        get => selectedIdx;
        set {
            if (selectedIdx == value) return;
            selectedIdx = Math.Max(-1, value);
            Invalidate();
            SelectedIndexChanged?.Invoke(this, EventArgs.Empty);
        }
    }

    public object? SelectedItem
    {
        get => selectedIdx >= 0 && selectedIdx < choices.Count ? choices[selectedIdx] : null;
        set {
            var s = value?.ToString();
            SelectedIndex = s == null ? -1 : choices.IndexOf(s);
        }
    }

    public event EventHandler? SelectedIndexChanged;

    public DropPicker()
    {
        Font = DP.F(14f);
        Cursor = Cursors.Hand;
        Height = 54;
        SetStyle(ControlStyles.UserPaint | ControlStyles.OptimizedDoubleBuffer | ControlStyles.AllPaintingInWmPaint | ControlStyles.ResizeRedraw, true);
    }

    public void SetItems(string[] items) { choices.Clear(); choices.AddRange(items); Invalidate(); }
    public void ClearItems() { choices.Clear(); selectedIdx = -1; Invalidate(); }

    protected override void OnMouseEnter(EventArgs e) { mouseOver = true;  Invalidate(); base.OnMouseEnter(e); }
    protected override void OnMouseLeave(EventArgs e) { mouseOver = false; Invalidate(); base.OnMouseLeave(e); }

    protected override void OnClick(EventArgs e)
    {
        base.OnClick(e);
        if (blockClick) return;
        if (flyout != null) { CloseFlyout(); return; }
        ShowFlyout();
    }

    void ShowFlyout()
    {
        if (choices.Count == 0) return;
        var pos = PointToScreen(new Point(0, Height - 1));
        flyout = new FlyoutList(choices, selectedIdx, Width, pos);
        flyout.ItemChosen += (_, i) => { SelectedIndex = i; CloseFlyout(); };
        flyout.Closed     += (_, _) => { flyout = null; Invalidate(); };
        flyout.Show(FindForm());
        Invalidate();
    }

    void CloseFlyout()
    {
        flyout?.Close();
        flyout = null;
        blockClick = true;
        var t = new System.Windows.Forms.Timer { Interval = 150 };
        t.Tick += (_, _) => { blockClick = false; t.Stop(); t.Dispose(); };
        t.Start();
        Invalidate();
    }

    protected override void OnPaint(PaintEventArgs e)
    {
        var g = e.Graphics;
        g.SmoothingMode = SmoothingMode.AntiAlias;
        g.TextRenderingHint = TextRenderingHint.ClearTypeGridFit;
        g.PixelOffsetMode = PixelOffsetMode.HighQuality;

        bool open = flyout != null;
        var bg  = open ? _brBgOpen : mouseOver ? _brBgHov : _brBgOff;
        var rim = open || mouseOver ? _penRimOn : _penRimOff;

        g.FillRectangle(bg,  new Rectangle(0, 0, Width - 1, Height - 1));
        g.DrawRectangle(rim, new Rectangle(0, 0, Width - 1, Height - 1));

        g.DrawString(SelectedItem?.ToString() ?? "", Font, _brItemFg,
            new RectangleF(9, 0, Width - 26, Height), _dpSf);

        int cx = Width - 13, cy = Height / 2;
        if (open) {
            _tri[0] = new PointF(cx - 3.5f, cy + 1.5f);
            _tri[1] = new PointF(cx + 3.5f, cy + 1.5f);
            _tri[2] = new PointF(cx,         cy - 2.5f);
        } else {
            _tri[0] = new PointF(cx - 3.5f, cy - 1.5f);
            _tri[1] = new PointF(cx + 3.5f, cy - 1.5f);
            _tri[2] = new PointF(cx,         cy + 2.5f);
        }
        g.FillPolygon(open ? _brArrOn : _brArrOff, _tri);
    }
}

internal class FlyoutList : Form
{
    static readonly Color bg      = Color.FromArgb(0x14, 0x14, 0x14);
    static readonly Color hoverBg = Color.FromArgb(0x1E, 0x1E, 0x1E);
    static readonly Color selBg   = Color.FromArgb(0x1B, 0x1B, 0x1B);
    static readonly Color border  = Color.FromArgb(0x28, 0x28, 0x28);
    static readonly Color textFg  = Color.FromArgb(0xE8, 0xE8, 0xE8);
    static readonly Color selFg   = Color.FromArgb(0xFF, 0xFF, 0xFF);
    static readonly Color sbBg    = Color.FromArgb(0x1A, 0x1A, 0x1A);
    static readonly Color sbFg    = Color.FromArgb(0x38, 0x38, 0x38);
    static readonly Color sbHov   = Color.FromArgb(0x4E, 0x4E, 0x4E);
    static readonly Font  rowFont = DP.F(14f);
    static readonly SolidBrush _brBg       = new(bg);
    static readonly SolidBrush _brHoverBg  = new(hoverBg);
    static readonly SolidBrush _brSelBg    = new(selBg);
    static readonly SolidBrush _brSelAccent = new(Color.FromArgb(0x3B, 0x82, 0xF6));
    static readonly SolidBrush _brTextFg   = new(textFg);
    static readonly SolidBrush _brSelFg    = new(selFg);
    static readonly SolidBrush _brSbBg     = new(sbBg);
    static readonly SolidBrush _brSbFg     = new(sbFg);
    static readonly SolidBrush _brSbHov    = new(sbHov);
    static readonly Pen _penBorder = new(border, 1f);
    static readonly StringFormat _rowSf = new() {
        LineAlignment = StringAlignment.Center,
        Trimming      = StringTrimming.EllipsisCharacter,
        FormatFlags   = StringFormatFlags.NoWrap,
    };

    const int ROW_H = 42, MAX_ROWS = 7, SB_W = 6;

    readonly List<string> options;
    readonly int currentSel;
    int hovered = -1, scrollTop = 0;
    bool sbHovered;

    public event EventHandler<int>? ItemChosen;

    public FlyoutList(List<string> items, int current, int width, Point screenPos)
    {
        options    = items;
        currentSel = current;

        int rows  = Math.Min(items.Count, MAX_ROWS);
        int totalH = rows * ROW_H + 2;

        FormBorderStyle = FormBorderStyle.None;
        StartPosition   = FormStartPosition.Manual;
        BackColor       = bg;
        ShowInTaskbar   = false;
        Size = new Size(width, totalH);

        var workArea = Screen.FromPoint(screenPos).WorkingArea;
        int y = screenPos.Y + totalH > workArea.Bottom
            ? screenPos.Y - totalH - 26
            : screenPos.Y;
        Location = new Point(screenPos.X, y);

        if (current > MAX_ROWS / 2)
            scrollTop = Math.Max(0, Math.Min(current - MAX_ROWS / 2, items.Count - MAX_ROWS));

        SetStyle(ControlStyles.UserPaint | ControlStyles.OptimizedDoubleBuffer | ControlStyles.AllPaintingInWmPaint | ControlStyles.ResizeRedraw, true);
        MouseMove  += HandleMouseMove;
        MouseLeave += (_, _) => { hovered = -1; sbHovered = false; Invalidate(); };
        MouseDown  += HandleClick;
        MouseWheel += HandleScroll;
        Deactivate += (_, _) => Close();
        KeyDown    += HandleKey;
    }

    protected override bool ShowWithoutActivation => false;

    int RowCount  => Math.Min(options.Count, MAX_ROWS);
    bool NeedsSB  => options.Count > MAX_ROWS;

    void HandleMouseMove(object? s, MouseEventArgs e)
    {
        bool inSB = NeedsSB && e.X >= Width - SB_W - 2;
        bool dirty = sbHovered != inSB;
        sbHovered = inSB;
        int idx = inSB ? -1 : (e.Y - 1) / ROW_H + scrollTop;
        if (idx != hovered && idx >= 0 && idx < options.Count) { hovered = idx; dirty = true; }
        if (dirty) Invalidate();
    }

    void HandleClick(object? s, MouseEventArgs e)
    {
        if (e.Button != MouseButtons.Left) return;
        if (NeedsSB && e.X >= Width - SB_W - 2) return;

        int idx = (e.Y - 1) / ROW_H + scrollTop;
        if (idx >= 0 && idx < options.Count) ItemChosen?.Invoke(this, idx);
    }

    void HandleScroll(object? s, MouseEventArgs e)
    {
        if (!NeedsSB) return;
        scrollTop = Math.Max(0, Math.Min(scrollTop - e.Delta / 120, options.Count - MAX_ROWS));
        Invalidate();
    }

    void HandleKey(object? s, KeyEventArgs e)
    {
        switch (e.KeyCode)
        {
            case Keys.Escape: Close(); break;
            case Keys.Up:     Nudge(-1); break;
            case Keys.Down:   Nudge(1);  break;
            case Keys.Return:
                if (hovered >= 0) ItemChosen?.Invoke(this, hovered);
                break;
        }
    }

    void Nudge(int dir)
    {
        int next = Math.Max(0, Math.Min((hovered < 0 ? currentSel : hovered) + dir, options.Count - 1));
        hovered = next;
        if (hovered < scrollTop) scrollTop = hovered;
        if (hovered >= scrollTop + MAX_ROWS) scrollTop = hovered - MAX_ROWS + 1;
        Invalidate();
    }

    protected override void OnPaint(PaintEventArgs e)
    {
        var g = e.Graphics;
        g.TextRenderingHint = TextRenderingHint.ClearTypeGridFit;
        g.SmoothingMode = SmoothingMode.AntiAlias;
        g.FillRectangle(_brBg, 0, 0, Width, Height);

        int textW = NeedsSB ? Width - SB_W - 10 : Width - 16;

        for (int vi = 0; vi < RowCount; vi++)
        {
            int di = vi + scrollTop;
            if (di >= options.Count) break;

            var rowRect = new Rectangle(1, vi * ROW_H + 1, Width - 2, ROW_H);
            bool isHov = di == hovered;
            bool isSel = di == currentSel;

            if (isHov)      g.FillRectangle(_brHoverBg, rowRect);
            else if (isSel) g.FillRectangle(_brSelBg,   rowRect);

            if (isSel)
                g.FillRectangle(_brSelAccent, new Rectangle(1, rowRect.Y, 2, rowRect.Height));

            g.DrawString(options[di], rowFont,
                isHov || isSel ? _brSelFg : _brTextFg,
                new RectangleF(10, rowRect.Y, textW, rowRect.Height), _rowSf);
        }

        if (NeedsSB)
        {
            int tx = Width - SB_W - 1, th = Height - 2;
            g.FillRectangle(_brSbBg, tx, 1, SB_W, th);
            float pct = (float)MAX_ROWS / options.Count;
            float pos = (float)scrollTop / options.Count;
            int tH = Math.Max(20, (int)(th * pct));
            int tY = 1 + (int)((th - tH) * pos);
            g.FillRectangle(sbHovered ? _brSbHov : _brSbFg, tx + 1, tY, SB_W - 2, tH);
        }

        g.DrawRectangle(_penBorder, 0, 0, Width - 1, Height - 1);
    }

    protected override void OnShown(EventArgs e) { base.OnShown(e); Focus(); }
}

public class SectionLabel : Control
{
    public SectionLabel()
    {
        Height = 20;
        SetStyle(ControlStyles.UserPaint | ControlStyles.OptimizedDoubleBuffer |
                 ControlStyles.AllPaintingInWmPaint | ControlStyles.ResizeRedraw, true);
    }

    protected override void OnPaint(PaintEventArgs e)
    {
        var g = e.Graphics;
        g.SmoothingMode     = SmoothingMode.AntiAlias;
        g.TextRenderingHint = TextRenderingHint.ClearTypeGridFit;
        g.Clear(BackColor);

        var sz = TextRenderer.MeasureText(g, Text, Font, Size.Empty,
            TextFormatFlags.NoPadding | TextFormatFlags.SingleLine);
        int ty = (Height - sz.Height) / 2;
        TextRenderer.DrawText(g, Text, Font, new Rectangle(0, ty, sz.Width + 2, sz.Height),
            Theme.AccentTint, TextFormatFlags.NoPadding | TextFormatFlags.SingleLine);

        int rx = sz.Width + 10, ry = Height / 2;
        if (rx < Width - 4)
        {
            using var grad = new LinearGradientBrush(
                new Point(rx, ry), new Point(Math.Max(rx + 1, Width - 4), ry),
                Color.FromArgb(90, Theme.Border.R, Theme.Border.G, Theme.Border.B),
                Color.FromArgb(0,  Theme.Border.R, Theme.Border.G, Theme.Border.B));
            using var pen = new Pen(grad, 1f);
            g.DrawLine(pen, rx, ry, Width - 4, ry);
        }
    }
}

public record WavFormat(ushort Tag, ushort Channels, uint SampleRate, ushort BitDepth)
{
    public uint   BytesPerSec  => SampleRate * Channels * BitDepth / 8u;
    public ushort BlockAlign   => (ushort)(Channels * BitDepth / 8);
}

public class LoopbackRecorder : IDisposable
{

    const int CLSCTX_ALL = 23, eRender = 0, eConsole = 1, STGM_READ = 0, SHARED_MODE = 0;
    const int S_OK = 0;
    const uint LOOPBACK_FLAG = 0x00020000, AUTOCONVERT = 0x80000000, SRC_QUALITY = 0x08000000;
    const uint SILENT_PACKET = 2;
    const int TARGET_SR = 44100;

    static readonly Guid MMDevEnum_CLSID  = new("BCDE0395-E52F-467C-8E3D-C4579291692E");
    static readonly Guid MMDevEnum_IID    = new("A95664D2-9614-4F35-A746-DE8DB63617E6");
    static readonly Guid AudioClient_IID  = new("1CB9AD4C-DBFA-4C32-B178-C2F568A703B2");
    static readonly Guid CapClient_IID    = new("C8ADBD64-E71E-48A0-A4DE-185C395CD317");
    static readonly Guid FriendlyName_Key = new("A45C254E-DF1C-4EFD-8020-67D146A850E0");
    const uint FriendlyName_PID = 14;

    readonly string? targetDevice;
    readonly Action<byte[], int> dataCallback;
    readonly bool captureMode;
    Thread? loopThread;
    volatile bool running;
    readonly ManualResetEventSlim startedEvent = new(false);

    public WavFormat? CaptureFormat { get; private set; }
    public int LatePackets { get; private set; }

    public LoopbackRecorder(string? deviceName, Action<byte[], int> onData, bool captureMode = false)
    {
        targetDevice = deviceName;
        dataCallback = onData;
        this.captureMode = captureMode;
    }

    public bool Start()
    {
        running    = true;
        loopThread = new Thread(ThreadMain) { IsBackground = true, Name = "wasapi-loopback" };
        loopThread.Start();
        bool started = startedEvent.Wait(3000);

        if (!started) {
            running = false;
            return false;
        }
        return true;
    }

    public void Stop() { running = false; loopThread?.Join(3000); }

    void ThreadMain()
    {
        CoInitializeEx(IntPtr.Zero, 0);

        try   { CaptureAudio(); }
        catch (Exception ex) { System.Diagnostics.Debug.WriteLine("loopback thread: " + ex.Message); }
        finally { CoUninitialize(); }
    }

    void CaptureAudio()
    {
        var clsid = MMDevEnum_CLSID; var iid = MMDevEnum_IID;
        if (CoCreateInstance(ref clsid, IntPtr.Zero, CLSCTX_ALL, ref iid, out var raw) != S_OK) return;
        var enumerator = (IMMDeviceEnumerator)raw;

        try
        {
            int flow = captureMode ? 1 : eRender;
            var device = targetDevice != null
                ? (FindDeviceByName(enumerator, targetDevice, flow) ?? GetDefault(enumerator, flow))
                : GetDefault(enumerator, flow);

            var acIID = AudioClient_IID;
            if (device.Activate(ref acIID, CLSCTX_ALL, IntPtr.Zero, out var clientRaw) != S_OK) return;
            var audioClient = (IAudioClient)clientRaw;

            try
            {
                if (audioClient.GetMixFormat(out var nativeFmtPtr) != S_OK) return;
                WAVEFORMATEX nativeFmt;
                try { nativeFmt = Marshal.PtrToStructure<WAVEFORMATEX>(nativeFmtPtr); }
                finally { Marshal.FreeCoTaskMem(nativeFmtPtr); }

                var wantedFmt = new WAVEFORMATEX {
                    wFormatTag      = 3,

                    nChannels       = 2,
                    nSamplesPerSec  = TARGET_SR,
                    wBitsPerSample  = 32,
                    nBlockAlign     = 8,
                    nAvgBytesPerSec = TARGET_SR * 8,
                    cbSize          = 0,
                };

                uint initFlags = captureMode ? AUTOCONVERT | SRC_QUALITY : LOOPBACK_FLAG | AUTOCONVERT | SRC_QUALITY;
                int hr = audioClient.Initialize(SHARED_MODE, initFlags, 10_000_000, 0, ref wantedFmt, IntPtr.Zero);

                if (hr != S_OK) {

                    uint fallbackFlags = captureMode ? 0u : LOOPBACK_FLAG;
                    hr = audioClient.Initialize(SHARED_MODE, fallbackFlags, 10_000_000, 0, ref nativeFmt, IntPtr.Zero);
                    if (hr != S_OK) return;
                    CaptureFormat = new WavFormat(nativeFmt.wFormatTag, nativeFmt.nChannels, nativeFmt.nSamplesPerSec, nativeFmt.wBitsPerSample);
                } else {
                    CaptureFormat = new WavFormat(3, 2, TARGET_SR, 32);
                }

                var ccIID = CapClient_IID;
                if (audioClient.GetService(ref ccIID, out var capRaw) != S_OK) return;
                var captureClient = (IAudioCaptureClient)capRaw;

                try
                {
                    audioClient.Start();
                    startedEvent.Set();
                    int frameBytes = CaptureFormat.BlockAlign;

                    while (running)
                    {
                        captureClient.GetNextPacketSize(out uint frameCount);
                        if (frameCount == 0) { Thread.Sleep(5); continue; }

                        int ghr = captureClient.GetBuffer(out var ptr, out uint nFrames, out uint flags, out _, out _);
                        if (ghr == S_OK && nFrames > 0)
                        {
                            int byteCount = (int)(nFrames * (uint)frameBytes);
                            var buf = GC.AllocateUninitializedArray<byte>(byteCount);

                            if ((flags & SILENT_PACKET) == 0 && ptr != IntPtr.Zero)
                                Marshal.Copy(ptr, buf, 0, byteCount);
                            dataCallback(buf, byteCount);
                            captureClient.ReleaseBuffer(nFrames);
                        }
                        else LatePackets++;
                    }

                    audioClient.Stop();
                }
                finally { Marshal.ReleaseComObject(captureClient); }
            }
            finally { Marshal.ReleaseComObject(audioClient); }
        }
        finally { Marshal.ReleaseComObject(enumerator); }
    }

    static IMMDevice GetDefault(IMMDeviceEnumerator e, int flow = eRender)
    {
        e.GetDefaultAudioEndpoint(flow, eConsole, out var d);
        return d;
    }

    static IMMDevice? FindDeviceByName(IMMDeviceEnumerator e, string name, int flow = eRender)
    {
        e.EnumAudioEndpoints(flow, 1, out var col);
        col.GetCount(out uint n);
        for (uint i = 0; i < n; i++)
        {
            col.Item(i, out var dev);
            bool match;
            try { match = GetFriendlyName(dev) == name; }
            catch { Marshal.ReleaseComObject(dev); throw; }
            if (match) return dev;
            Marshal.ReleaseComObject(dev);
        }
        return null;
    }

    static string? GetFriendlyName(IMMDevice dev)
    {
        try {
            dev.OpenPropertyStore(STGM_READ, out var store);
            try {
                var k = new PROPKEY { fmtid = FriendlyName_Key, pid = FriendlyName_PID };
                store.GetValue(ref k, out var pv);
                const ushort VT_LPWSTR = 31;
                if (pv.vt == VT_LPWSTR) return Marshal.PtrToStringUni(pv.ptr);
            } finally { Marshal.ReleaseComObject(store); }
        }
        catch (COMException) { }
        return null;
    }

    public static string? DefaultOutputDeviceName()
    {
        CoInitializeEx(IntPtr.Zero, 0);
        try {
            var c = MMDevEnum_CLSID; var i = MMDevEnum_IID;
            if (CoCreateInstance(ref c, IntPtr.Zero, CLSCTX_ALL, ref i, out var raw) != S_OK) return null;
            var e = (IMMDeviceEnumerator)raw;
            var d = GetDefault(e);
            var name = GetFriendlyName(d);
            Marshal.ReleaseComObject(d);
            Marshal.ReleaseComObject(e);
            return name;
        }
        finally { CoUninitialize(); }
    }

    public static List<string> ListOutputDevices()
    {
        var result = new List<string>();
        CoInitializeEx(IntPtr.Zero, 0);
        try {
            var c = MMDevEnum_CLSID; var i = MMDevEnum_IID;
            if (CoCreateInstance(ref c, IntPtr.Zero, CLSCTX_ALL, ref i, out var raw) != S_OK) return result;
            var e = (IMMDeviceEnumerator)raw;
            e.EnumAudioEndpoints(eRender, 1, out var col);
            col.GetCount(out uint n);
            for (uint j = 0; j < n; j++) {
                col.Item(j, out var dev);
                try { var n2 = GetFriendlyName(dev); if (n2 != null) result.Add(n2); }
                finally { Marshal.ReleaseComObject(dev); }
            }
            Marshal.ReleaseComObject(e);
        }
        finally { CoUninitialize(); }
        return result;
    }

    public static List<string> ListInputDevices()
    {
        var result = new List<string>();
        CoInitializeEx(IntPtr.Zero, 0);
        try {
            var c = MMDevEnum_CLSID; var i = MMDevEnum_IID;
            if (CoCreateInstance(ref c, IntPtr.Zero, CLSCTX_ALL, ref i, out var raw) != S_OK) return result;
            var e = (IMMDeviceEnumerator)raw;
            e.EnumAudioEndpoints(1, 1, out var col);  
            col.GetCount(out uint n);
            for (uint j = 0; j < n; j++) {
                col.Item(j, out var dev);
                try { var n2 = GetFriendlyName(dev); if (n2 != null) result.Add(n2); }
                finally { Marshal.ReleaseComObject(dev); }
            }
            Marshal.ReleaseComObject(e);
        }
        finally { CoUninitialize(); }
        return result;
    }

    public void Dispose() => Stop();

    [DllImport("ole32.dll")] static extern int  CoInitializeEx(IntPtr r, int apt);
    [DllImport("ole32.dll")] static extern void CoUninitialize();
    [DllImport("ole32.dll")] static extern int  CoCreateInstance(ref Guid cls, IntPtr outer, int ctx, ref Guid iid,
        [MarshalAs(UnmanagedType.IUnknown)] out object ppv);

