public class ScreenGrabber
{
    [DllImport("user32.dll")] static extern bool GetCursorInfo(out CURSORINFO pci);
    [DllImport("user32.dll")] static extern bool DrawIconEx(IntPtr hdc, int x, int y, IntPtr hIcon, int cxW, int cyH, int step, IntPtr hBrush, uint flags);
    [StructLayout(LayoutKind.Sequential)] struct POINT { public int X, Y; }
    [StructLayout(LayoutKind.Sequential)] struct CURSORINFO { public int cbSize, flags; public IntPtr hCursor; public POINT pt; }
    const int CURSOR_SHOWING = 1; const uint DI_NORMAL = 3;

    readonly Rectangle captureRect;
    readonly Size outputSize;
    readonly int targetFps;
    readonly Action<byte[], double> frameCallback;
    readonly CancellationToken cancel;
    readonly bool drawCursor;

    const int JpegQuality = 78;

    static readonly ImageCodecInfo  JpegEncoder  = ImageCodecInfo.GetImageEncoders().First(c => c.FormatID == ImageFormat.Jpeg.Guid);
    static readonly EncoderParameters EncParams  = new EncoderParameters(1) { Param = { [0] = new EncoderParameter(Encoder.Quality, (long)JpegQuality) } };

    static readonly int _cursorInfoSize = Marshal.SizeOf<CURSORINFO>();

    public int DroppedFrames { get; private set; }
    public double ActualFps  { get; private set; }

    uint _prevHash;
    bool _hasPrevHash;

    public ScreenGrabber(Rectangle region, Size outSize, int fps, Action<byte[], double> onFrame, CancellationToken ct, bool drawCursor = true)
    {
        captureRect    = region;
        outputSize     = outSize;
        targetFps      = fps;
        frameCallback  = onFrame;
        cancel         = ct;
        this.drawCursor = drawCursor;
    }

    // Fast FNV-1a bitmap hash: samples a grid of pixels to detect static frames cheaply (~0.5ms).
    static uint BitmapHash(Bitmap bmp)
    {
        var data = bmp.LockBits(new Rectangle(0, 0, bmp.Width, bmp.Height),
                                 ImageLockMode.ReadOnly, PixelFormat.Format32bppArgb);
        try {
            int stepX = Math.Max(1, data.Width  / 32);
            int stepY = Math.Max(1, data.Height / 24);
            uint hash = 2166136261u;
            for (int y = 0; y < data.Height; y += stepY)
                for (int x = 0; x < data.Width; x += stepX)
                    hash = (hash ^ (uint)Marshal.ReadInt32(data.Scan0, y * data.Stride + x * 4)) * 16777619u;
            return hash;
        } finally { bmp.UnlockBits(data); }
    }

    public void Run()
    {
        bool needsScale = outputSize.Width != captureRect.Width || outputSize.Height != captureRect.Height;

        using var bmp       = new Bitmap(captureRect.Width, captureRect.Height, PixelFormat.Format32bppArgb);
        using var gfx       = Graphics.FromImage(bmp);
        using var ms        = new MemoryStream(256 * 1024);
        using var scaled    = needsScale ? new Bitmap(outputSize.Width, outputSize.Height, PixelFormat.Format32bppArgb) : null;
        using var scaledGfx = scaled != null ? Graphics.FromImage(scaled) : null;
        if (scaledGfx != null)
        {
            scaledGfx.InterpolationMode = System.Drawing.Drawing2D.InterpolationMode.Low;
            scaledGfx.SmoothingMode     = System.Drawing.Drawing2D.SmoothingMode.None;
            scaledGfx.PixelOffsetMode   = System.Drawing.Drawing2D.PixelOffsetMode.None;
        }

        var interval = TimeSpan.FromSeconds(1.0 / targetFps);
        var nextTick = DateTime.UtcNow;
        int frameCount = 0;
        var fpsTimer   = DateTime.UtcNow;

        while (!cancel.IsCancellationRequested)
        {
            var now = DateTime.UtcNow;
            double ts = (now - DateTime.UnixEpoch).TotalSeconds;

            try { gfx.CopyFromScreen(captureRect.Location, Point.Empty, captureRect.Size); }
            catch (System.ComponentModel.Win32Exception)
            {
                DroppedFrames++;
                Thread.Sleep(33);
                continue;
            }
            if (drawCursor) {
                var ci = new CURSORINFO { cbSize = _cursorInfoSize };
                if (GetCursorInfo(out ci) && (ci.flags & CURSOR_SHOWING) != 0) {
                    int cx = ci.pt.X - captureRect.X, cy = ci.pt.Y - captureRect.Y;
                    if (cx > -64 && cx < captureRect.Width + 64 && cy > -64 && cy < captureRect.Height + 64) {
                        var hdc = gfx.GetHdc();
                        try { DrawIconEx(hdc, cx, cy, ci.hCursor, 0, 0, 0, IntPtr.Zero, DI_NORMAL); }
                        finally { gfx.ReleaseHdc(hdc); }
                    }
                }
            }

            Bitmap toEncode = bmp;
            if (needsScale) {
                scaledGfx!.DrawImage(bmp, 0, 0, outputSize.Width, outputSize.Height);
                toEncode = scaled!;
            }

            // Static-frame skip: hash the captured bitmap; if identical to previous, skip JPEG encode.
            // FFmpeg's -vf fps filter will repeat the last frame to fill the gap in the output clip.
            uint fh = BitmapHash(bmp);
            bool isNew = !_hasPrevHash || fh != _prevHash;
            _prevHash = fh; _hasPrevHash = true;
            if (isNew) {
                ms.SetLength(0);
                toEncode.Save(ms, JpegEncoder, EncParams);
                int frameLen = (int)ms.Length;
                var frame = GC.AllocateUninitializedArray<byte>(frameLen);
                ms.GetBuffer().AsSpan(0, frameLen).CopyTo(frame);
                frameCallback(frame, ts);
            }

            frameCount++;
            var nowAfter = DateTime.UtcNow;
            if ((nowAfter - fpsTimer).TotalSeconds >= 1.0) {
                ActualFps = frameCount;
                frameCount = 0;
                fpsTimer = nowAfter;
            }

            nextTick += interval;
            var delay = nextTick - nowAfter;
            if (delay > TimeSpan.Zero) Thread.Sleep(delay);
            else DroppedFrames++;
        }
    }

    public static Size ScaleToHeight(Rectangle monitor, string label)
    {
        int targetH = label switch { "360p" => 360, "720p" => 720, _ => 1080 };
        if (monitor.Height <= targetH) return monitor.Size;
        double ratio = (double)targetH / monitor.Height;
        return new Size((int)(monitor.Width * ratio) & ~1, (int)(monitor.Height * ratio) & ~1);
    }
}

static class ClipEncoder
{
    public static void WriteClip(
        IList<(double ts, byte[] jpg)> videoFrames,
        IList<(double ts, byte[] pcm)> audioChunks,
        WavFormat? audioFmt,
        IList<(double ts, byte[] pcm)> micChunks,
        WavFormat? micFmt,
        int fps, string outputDir, string ffmpegPath, string format, string encoder,
        string baseName = "clip", int crf = 23,
        Action<bool, string>? onFinished = null)
    {
        if (videoFrames.Count == 0) {
            onFinished?.Invoke(false, "No frames buffered yet — wait a moment after startup");
            return;
        }

        try {
            var drive = new DriveInfo(Path.GetPathRoot(outputDir) ?? "C:\\");
            int clipSecs = videoFrames.Count > 1
                ? (int)(videoFrames[^1].ts - videoFrames[0].ts) + 1
                : 30;
            long estimatedBytes = (long)(clipSecs * (fps >= 30 ? 5_500_000L : 2_800_000L));
            if (drive.AvailableFreeSpace < estimatedBytes * 2)
                onFinished?.Invoke(false, $"Not enough disk space: {drive.AvailableFreeSpace / 1_000_000}MB free, need ~{estimatedBytes * 2 / 1_000_000}MB");
        }
        catch (Exception) {  }

        try { Directory.CreateDirectory(outputDir); }
        catch (UnauthorizedAccessException ex) {
            onFinished?.Invoke(false, $"Can't write to {outputDir}: {ex.Message}");
            return;
        }

        string stamp   = DateTime.Now.ToString("yyyyMMdd_HHmmss");
        string wavTmp  = Path.Combine(outputDir, $".tmp_audio_{stamp}.wav");
        string outFile = Path.Combine(outputDir, $"{baseName}.{format}");

        bool withAudio = audioChunks.Count > 0 && audioFmt != null;
        bool withMic   = micChunks.Count > 0 && micFmt != null;
        if (withAudio) WriteWav(wavTmp, audioChunks, audioFmt!);
        string micWavTmp = Path.Combine(outputDir, $".tmp_mic_{stamp}.wav");
        if (withMic) WriteWav(micWavTmp, micChunks, micFmt!);

        double realFps = fps;
        if (videoFrames.Count >= 2) {
            double span = videoFrames[^1].ts - videoFrames[0].ts;
            if (span > 0.5) realFps = Math.Max(1.0, (videoFrames.Count - 1) / span);
        }

        var args = new List<string> {
            "-y", "-f", "image2pipe",
            "-framerate", realFps.ToString("F4", System.Globalization.CultureInfo.InvariantCulture),
            "-i", "pipe:0"
        };
        if (withAudio) { args.Add("-i"); args.Add($"\"{wavTmp}\""); }
        if (withMic)   { args.Add("-i"); args.Add($"\"{micWavTmp}\""); }
        switch (encoder) {
            case "h264_nvenc":
                args.AddRange(["-c:v", "h264_nvenc", "-preset", "p1", "-rc", "vbr", "-cq", crf.ToString(), "-vf", $"fps={fps}"]);
                break;
            case "h264_amf":
                args.AddRange(["-c:v", "h264_amf", "-quality", "speed", "-qp_i", crf.ToString(), "-qp_p", crf.ToString(), "-vf", $"fps={fps}"]);
                break;
            case "h264_qsv":
                args.AddRange(["-c:v", "h264_qsv", "-preset", "veryfast", "-global_quality", crf.ToString(), "-vf", $"fps={fps}"]);
                break;
            default:
                args.AddRange(["-c:v", "libx264", "-preset", "ultrafast", "-crf", crf.ToString(), "-vf", $"fps={fps}"]);
                break;
        }
        if (withAudio && withMic)
            args.AddRange(["-filter_complex", "amix=inputs=2:duration=shortest", "-c:a", "aac", "-b:a", "192k", "-shortest"]);
        else if (withAudio || withMic)
            args.AddRange(["-c:a", "aac", "-b:a", "192k", "-shortest"]);
        args.Add($"\"{outFile}\"");

        var psi = new ProcessStartInfo(ffmpegPath, string.Join(" ", args)) {
            UseShellExecute       = false,
            RedirectStandardInput = true,
            RedirectStandardError = true,
            CreateNoWindow        = true,
        };

        Process? proc;
        try { proc = Process.Start(psi); }
        catch (Exception ex) { onFinished?.Invoke(false, "ffmpeg wouldn't start: " + ex.Message); return; }
        if (proc == null) { onFinished?.Invoke(false, "ffmpeg process failed to start"); return; }

        using (proc)
        {
            var stderrReader = proc.StandardError.ReadToEndAsync();

            var frameSnapshot = videoFrames.ToArray();
            var feeder = new Thread(() => {
                try {
                    foreach (var f in frameSnapshot)
                        proc.StandardInput.BaseStream.Write(f.jpg);
                }
                catch (IOException) {  }
                finally {
                    try { proc.StandardInput.Close(); } catch { }
                }
            }) { IsBackground = true };
            feeder.Start();

            string stderr = stderrReader.GetAwaiter().GetResult();
            proc.WaitForExit();
            feeder.Join(2000);

            if (withAudio) { try { File.Delete(wavTmp);    } catch { } }
            if (withMic)   { try { File.Delete(micWavTmp); } catch { } }

            if (proc.ExitCode == 0)
            {

                string sizeStr = "";
                try {
                    long bytes = new FileInfo(outFile).Length;
                    sizeStr = bytes > 1_000_000 ? $" ({bytes / 1_000_000.0:F1}MB)" : $" ({bytes / 1000}KB)";
                }
                catch { }
                onFinished?.Invoke(true, outFile + sizeStr);
            }
            else
            {

                string errSnip = stderr.Length > 300 ? "…" + stderr[^300..] : stderr;
                onFinished?.Invoke(false, errSnip);
            }
        }
    }

    public static string ProbeEncoder(string ffmpegPath)
    {
        foreach (var enc in new[] { "h264_nvenc", "h264_amf", "h264_qsv" }) {
            try {
                var psi = new ProcessStartInfo(ffmpegPath,
                    $"-f lavfi -i nullsrc=s=64x64:d=0.1 -c:v {enc} -f null -") {
                    UseShellExecute = false, RedirectStandardError = true, CreateNoWindow = true,
                };
                using var p = Process.Start(psi)!;
                if (!p.WaitForExit(5000)) { p.Kill(); p.WaitForExit(); }
                if (p.ExitCode == 0) return enc;
            } catch { }
        }
        return "libx264";
    }

    static void WriteWav(string path, IList<(double, byte[])> chunks, WavFormat fmt)
    {
        int totalBytes = 0;
        foreach (var (_, pcm) in chunks) totalBytes += pcm.Length;
        using var fs = new FileStream(path, FileMode.Create);
        using var bw = new BinaryWriter(fs);
        bw.Write("RIFF"u8);
        bw.Write(36 + totalBytes);
        bw.Write("WAVE"u8);
        bw.Write("fmt "u8);
        bw.Write(16);
        bw.Write(fmt.Tag); bw.Write(fmt.Channels);
        bw.Write(fmt.SampleRate); bw.Write(fmt.BytesPerSec);
        bw.Write(fmt.BlockAlign); bw.Write(fmt.BitDepth);
        bw.Write("data"u8);
        bw.Write(totalBytes);
        foreach (var (_, pcm) in chunks) bw.Write(pcm);
    }
}

sealed class TrimBar : Control
{
    public double Duration   { get; private set; } = 30;
    public double TrimStart  { get; private set; } = 0;
    public double TrimEnd    { get; private set; } = 30;
    public event EventHandler? Changed;

    static readonly SolidBrush _brTrack  = new(Color.FromArgb(0x28, 0x28, 0x28));
    static readonly SolidBrush _brActive = new(Color.FromArgb(0x3B, 0x82, 0xF6));
    static readonly SolidBrush _brCut    = new(Color.FromArgb(0x0C, 0x0C, 0x0C));
    static readonly SolidBrush _brHandle = new(Color.FromArgb(0xEE, 0xEE, 0xEE));
    static readonly SolidBrush _brLbl    = new(Color.FromArgb(0x3B, 0x82, 0xF6));
    static readonly Font         _fnt = DP.F(8f);
    static readonly StringFormat _sfT = new() { Alignment = StringAlignment.Center, LineAlignment = StringAlignment.Far };
    static readonly StringFormat _sfB = new() { Alignment = StringAlignment.Center, LineAlignment = StringAlignment.Near };
    const int PAD = 14, HW = 5, TH = 6;
    int _drag;

    public TrimBar() { Height = 44; DoubleBuffered = true; }

    public void SetRange(double dur) { Duration = TrimEnd = dur; TrimStart = 0; Invalidate(); }

    int  ToX(double t) => PAD + (int)((t / Math.Max(Duration, 0.001)) * (Width - PAD * 2));
    double FromX(int x) => Math.Clamp((double)(x - PAD) / Math.Max(Width - PAD * 2, 1), 0, 1) * Duration;

    protected override void OnMouseDown(MouseEventArgs e)
    {
        int xs = ToX(TrimStart), xe = ToX(TrimEnd);
        if (Math.Abs(e.X - xs) <= HW + 4) _drag = 1;
        else if (Math.Abs(e.X - xe) <= HW + 4) _drag = 2;
    }
    protected override void OnMouseMove(MouseEventArgs e)
    {
        int xs = ToX(TrimStart), xe = ToX(TrimEnd);
        Cursor = (Math.Abs(e.X - xs) <= HW + 4 || Math.Abs(e.X - xe) <= HW + 4) ? Cursors.SizeWE : Cursors.Default;
        if (e.Button != MouseButtons.Left || _drag == 0) return;
        double t = FromX(e.X);
        if (_drag == 1) TrimStart = Math.Min(t, TrimEnd - 0.1);
        else            TrimEnd   = Math.Max(t, TrimStart + 0.1);
        Changed?.Invoke(this, EventArgs.Empty);
        Invalidate();
    }
    protected override void OnMouseUp(MouseEventArgs e) { _drag = 0; }

    protected override void OnPaint(PaintEventArgs e)
    {
        var g = e.Graphics;
        g.SmoothingMode = SmoothingMode.AntiAlias;
        g.TextRenderingHint = System.Drawing.Text.TextRenderingHint.ClearTypeGridFit;
        g.Clear(Color.FromArgb(0x12, 0x12, 0x12));
        int mid = Height / 2, xs = ToX(TrimStart), xe = ToX(TrimEnd);
        g.FillRectangle(_brTrack,  PAD, mid - TH/2, Width - PAD*2, TH);
        g.FillRectangle(_brCut,    PAD, mid - TH/2, xs - PAD,      TH);
        g.FillRectangle(_brCut,    xe,  mid - TH/2, Width - PAD - xe, TH);
        g.FillRectangle(_brActive, xs,  mid - TH/2, xe - xs, TH);
        g.FillRectangle(_brHandle, xs - HW/2, mid - 10, HW, 20);
        g.FillRectangle(_brHandle, xe - HW/2, mid - 10, HW, 20);
        g.DrawString($"{TrimStart:F1}s", _fnt, _brLbl, new RectangleF(xs - 28, 0, 56, mid - 3), _sfT);
        g.DrawString($"{TrimEnd:F1}s",   _fnt, _brLbl, new RectangleF(xe - 28, mid + 3, 56, mid - 3), _sfB);
    }
}

public sealed class ClipEditorForm : Form
{
    static readonly Color BG   = Color.FromArgb(0x12, 0x12, 0x12);
    static readonly Color TBAR = Color.FromArgb(0x09, 0x09, 0x09);
    static readonly Color ACCT = Color.FromArgb(0x3B, 0x82, 0xF6);
    static readonly Color DIV  = Color.FromArgb(0x26, 0x26, 0x26);
    static readonly Color FG   = Color.FromArgb(0xE8, 0xE8, 0xE8);
    static readonly Color FG2  = Color.FromArgb(0x60, 0x60, 0x60);
    static readonly Color FG3  = Color.FromArgb(0x40, 0x40, 0x40);

    readonly string _ffmpeg;
    string _clip, _backup;
    bool _busy;

    TrimBar     _trim      = null!;
    CheckBox    _muteAudio = null!;
    Label       _status    = null!;
    Label       _fileLabel = null!;
    RoundButton _saveBtn   = null!;

    [DllImport("dwmapi.dll")] static extern int DwmSetWindowAttribute(IntPtr hwnd, int attr, ref int val, int size);
    static readonly System.Text.RegularExpressions.Regex _durRx =
        new(@"Duration:\s*(\d+):(\d+):(\d+\.?\d*)", System.Text.RegularExpressions.RegexOptions.Compiled);

    public ClipEditorForm(string clipPath, string ffmpegPath)
    {
        _ffmpeg = ffmpegPath;
        _clip   = clipPath;
        _backup = MakeBackupPath(clipPath);
        FormBorderStyle = FormBorderStyle.None;
        BackColor       = BG;
        StartPosition   = FormStartPosition.CenterScreen;
        Width           = 540;
        TopMost         = true;
        Build();
        Shown += async (_, _) => {
            try { int v = 2; DwmSetWindowAttribute(Handle, 33, ref v, sizeof(int)); } catch { }
            await LoadDurationAsync();
        };
    }

    static string MakeBackupPath(string clip) =>
        Path.Combine(Path.GetDirectoryName(clip)!,
                     Path.GetFileNameWithoutExtension(clip) + "_orig" + Path.GetExtension(clip));

    void LoadClip(string path)
    {
        _clip   = path;
        _backup = MakeBackupPath(path);
        string fname = Path.GetFileName(path);
        _fileLabel.Text = fname.Length > 62 ? "…" + fname[^59..] : fname;
        _trim.SetRange(0);
        _status.Text = "Loading…";
        _ = LoadDurationAsync();
    }

    void BrowseClip()
    {
        using var dlg = new OpenFileDialog {
            Filter = "Video files|*.mp4;*.mkv;*.avi;*.mov;*.wmv|All files|*.*",
            Title  = "Choose a clip to edit",
        };
        if (dlg.ShowDialog() == DialogResult.OK) LoadClip(dlg.FileName);
    }

    void Build()
    {
        int y = 0;
        Controls.Add(new Panel { Location = Point.Empty, Size = new Size(Width, 2), BackColor = ACCT });
        y += 2;

        var tb = new Panel { Location = new Point(0, y), Size = new Size(Width, 32), BackColor = TBAR };
        tb.Controls.Add(new Label { Text = "Edit Clip", ForeColor = FG, Font = DP.F(11f), BackColor = TBAR,
            Location = new Point(14, 0), Size = new Size(200, 32), TextAlign = ContentAlignment.MiddleLeft });
        var xBtn = new Label { Text = "×", ForeColor = FG2, Font = DP.F(9f), BackColor = TBAR,
            Size = new Size(32, 32), TextAlign = ContentAlignment.MiddleCenter, Left = Width - 32, Cursor = Cursors.Hand };
        xBtn.Click += (_, _) => Close();
        xBtn.MouseEnter += (_, _) => xBtn.BackColor = Color.FromArgb(0xC4, 0x2B, 0x1D);
        xBtn.MouseLeave += (_, _) => xBtn.BackColor = TBAR;
        tb.Controls.Add(xBtn);
        Point _dp = default;
        tb.MouseDown += (_, e) => { if (e.Button == MouseButtons.Left) _dp = e.Location; };
        tb.MouseMove += (_, e) => { if (e.Button == MouseButtons.Left) { Left += e.X - _dp.X; Top += e.Y - _dp.Y; } };
        Controls.Add(tb);
        y += 32;

        Div(ref y);

        // file info row with browse button
        y += 6;
        string fname = Path.GetFileName(_clip);
        _fileLabel = new Label { Text = fname.Length > 62 ? "…" + fname[^59..] : fname,
            ForeColor = FG2, Font = DP.F(9f), BackColor = BG,
            Location = new Point(14, y), Size = new Size(Width - 90, 18), AutoEllipsis = true };
        Controls.Add(_fileLabel);
        Controls.Add(new RoundButton("Browse…", BrowseClip, 68, 22) {
            Location = new Point(Width - 76, y - 2), Font = DP.F(8f)
        });
        y += 24;

        Div(ref y);
        Head("TRIM", ref y);

        _trim = new TrimBar { Location = new Point(14, y), Size = new Size(Width - 28, 44) };
        _trim.Changed += (_, _) => RefreshStatus();
        Controls.Add(_trim);
        y += 48;

        Div(ref y);
        Head("AUDIO", ref y);

        _muteAudio = new CheckBox { Text = "Mute audio track", ForeColor = FG2, BackColor = BG,
            Font = DP.F(9f), AutoSize = true, Location = new Point(14, y), FlatStyle = FlatStyle.Flat };
        _muteAudio.FlatAppearance.BorderSize = 0;
        _muteAudio.FlatAppearance.CheckedBackColor = Color.Transparent;
        Controls.Add(_muteAudio);
        y += 24;

        Div(ref y);
        y += 4;

        _status = new Label { Text = "Loading…", ForeColor = FG3, Font = DP.F(8f), BackColor = BG,
            Location = new Point(14, y), Size = new Size(Width - 28, 14) };
        Controls.Add(_status);
        y += 18;

        int bw = Width / 3;
        Controls.Add(new RoundButton("Preview", OpenPreview, bw, 30) { Location = new Point(0, y), Font = DP.F(11f) });
        _saveBtn = new RoundButton("Save", DoSave, bw, 30) { Location = new Point(bw, y), Font = DP.F(11f) };
        Controls.Add(_saveBtn);
        Controls.Add(new RoundButton("Revert", DoRevert, Width - bw * 2, 30) { Location = new Point(bw * 2, y), Font = DP.F(11f) });
        y += 32;

        Height = y + 4;
    }

    void Div(ref int y) { Controls.Add(new Panel { Location = new Point(0, y), Size = new Size(Width, 1), BackColor = DIV }); y++; }
    void Head(string t, ref int y) { y += 4; Controls.Add(new Label { Text = t, ForeColor = FG3, Font = DP.F(7f), BackColor = BG, Location = new Point(14, y), AutoSize = true }); y += 12; }

    async Task LoadDurationAsync()
    {
        try {
            var psi = new ProcessStartInfo(_ffmpeg, $"-i \"{_clip}\" -hide_banner") {
                UseShellExecute = false, RedirectStandardError = true, CreateNoWindow = true
            };
            using var p = Process.Start(psi)!;
            string err = await p.StandardError.ReadToEndAsync();
            p.WaitForExit(5000);
            var m = _durRx.Match(err);
            if (m.Success) {
                double dur = int.Parse(m.Groups[1].Value) * 3600
                           + int.Parse(m.Groups[2].Value) * 60
                           + double.Parse(m.Groups[3].Value, System.Globalization.CultureInfo.InvariantCulture);
                if (IsHandleCreated) BeginInvoke(() => { _trim.SetRange(dur); RefreshStatus(); });
            } else if (IsHandleCreated)
                BeginInvoke(() => _status.Text = "Couldn't read duration");
        } catch (Exception ex) {
            if (IsHandleCreated) BeginInvoke(() => _status.Text = $"Error: {ex.Message}");
        }
    }

    void RefreshStatus() => _status.Text = $"{_trim.TrimStart:F1}s → {_trim.TrimEnd:F1}s  ({_trim.TrimEnd - _trim.TrimStart:F1}s)";

    void OpenPreview() { try { Process.Start(new ProcessStartInfo(_clip) { UseShellExecute = true }); } catch { } }

    void DoSave()
    {
        if (_busy) return;
        if (!File.Exists(_backup)) { try { File.Copy(_clip, _backup, false); } catch { } }
        _busy = true;
        _saveBtn.Enabled = false;
        _status.Text = "Saving…";

        double start = _trim.TrimStart, end = _trim.TrimEnd;
        bool mute = _muteAudio.Checked;
        string tmp = _clip + ".tmp" + Path.GetExtension(_clip);

        Task.Run(() => {
            try {
                var args = new List<string> {
                    "-y",
                    "-ss", start.ToString("F3", System.Globalization.CultureInfo.InvariantCulture),
                    "-i", $"\"{_clip}\"",
                    "-to", (end - start).ToString("F3", System.Globalization.CultureInfo.InvariantCulture),
                    "-c", "copy",
                };
                if (mute) args.Add("-an");
                args.Add($"\"{tmp}\"");

                var psi = new ProcessStartInfo(_ffmpeg, string.Join(" ", args)) {
                    UseShellExecute = false, RedirectStandardError = true, CreateNoWindow = true
                };
                using var p = Process.Start(psi)!;
                string err = p.StandardError.ReadToEnd();
                p.WaitForExit();

                if (p.ExitCode == 0) {
                    File.Delete(_clip); File.Move(tmp, _clip);
                    BeginInvoke(() => { _status.Text = "Saved."; _saveBtn.Enabled = true; _busy = false; _ = LoadDurationAsync(); });
                } else {
                    try { File.Delete(tmp); } catch { }
                    string snip = err.Length > 80 ? err[^80..] : err;
                    BeginInvoke(() => { _status.Text = $"Failed: {snip}"; _saveBtn.Enabled = true; _busy = false; });
                }
            } catch (Exception ex) {
                BeginInvoke(() => { _status.Text = $"Error: {ex.Message}"; _saveBtn.Enabled = true; _busy = false; });
            }
        });
    }

    void DoRevert()
    {
        if (_busy) return;
        if (!File.Exists(_backup)) { _status.Text = "No backup — save the clip first to create one"; return; }
        try {
            File.Delete(_clip); File.Copy(_backup, _clip);
            _status.Text = "Reverted to original.";
            _ = LoadDurationAsync();
        } catch (Exception ex) { _status.Text = $"Revert failed: {ex.Message}"; }
    }
}

public class SidebarOverlay : Form
{
    const int TAB_W   = 28;
    const int PANEL_W = 400;
    const int PAD     = 20;
    const int LABEL_W = 112;
    const int ROW_H   = 52;
    const int CTRL_H  = 36;
    const int LBL_H   = 16;
    const int FOOTER_H = 48;
    const int BORDER_W = 1;
    const int QUIT_H   = 104;

    static readonly Color SBG    = Theme.Base;
    static readonly Color STABBG = Theme.Surface;
    static readonly Color SDIV   = Theme.Border;
    static readonly Color SACCT  = Theme.Accent;
    static readonly Color SFG    = Theme.TextPrimary;
    static readonly Color SFG2   = Theme.TextSecondary;
    static readonly Color SFG3   = Theme.TextTertiary;
    static readonly Color STBAR  = Color.FromArgb(0x08, 0x09, 0x0C);
    static readonly Color SREDD  = Color.FromArgb(0xF0, 0x45, 0x45);
    static readonly SolidBrush _brSacct  = new(Color.FromArgb(0x3B, 0x82, 0xF6));
    static readonly SolidBrush _brSRedd  = new(Color.FromArgb(0xF0, 0x40, 0x40));
    static readonly SolidBrush _brDimDot = new(Color.FromArgb(0x40, 0x40, 0x40));
    static readonly StringFormat _tabSf  = new() { Alignment = StringAlignment.Center, LineAlignment = StringAlignment.Center };
    static readonly Font  SSF9   = DP.F(9f);
    static readonly Font  SSF8   = DP.F(8f);
    static readonly Font  SSF7   = DP.F(7f);

    static readonly Dictionary<string, int> SDurationMap = new() {
        ["5 sec"] = 5, ["10 sec"] = 10, ["15 sec"] = 15, ["30 sec"] = 30, ["1 min"] = 60,
    };

    bool expanded;
    int  collapsedLeft, expandedLeft, layoutY;

    readonly MainForm owner;

    Panel         contentPanel = null!;
    Label         timeLabel    = null!;
    Label         ramLabel     = null!;
    Label         statusLabel  = null!;
    DropPicker    monPicker    = null!, resPicker  = null!, fpsPicker = null!,
                  audPicker    = null!, micPicker  = null!, durPicker = null!,
                  fmtPicker    = null!, curPicker  = null!;
    HotkeyCapture clipHkInput  = null!;
    HotkeyCapture sbarHkInput  = null!;
    StyledTextBox saveDirInput = null!;
    RoundButton   previewBtn      = null!;
    RoundButton   openFolderBtn   = null!;
    RoundButton   editBtn         = null!;
    RoundButton   clipBtn         = null!;
    int           clipBtnY;
    readonly int[] sepY    = new int[8];
    int            sepCount;
    Label         frameDropLabel = null!;
    DropPicker    crfPicker      = null!;

    static readonly Dictionary<string, int> CrfMap = new() {
        ["18 – High"] = 18, ["23 – Default"] = 23, ["28 – Small"] = 28, ["35 – Compact"] = 35
    };

    System.Windows.Forms.Timer slideTimer = null!;

    public SidebarOverlay(MainForm owner, Rectangle monitorRect)
    {
        this.owner = owner;

        FormBorderStyle = FormBorderStyle.None;
        StartPosition   = FormStartPosition.Manual;
        TopMost         = true;
        ShowInTaskbar   = true;
        Text            = "Atlas";
        if (owner.Icon != null) Icon = owner.Icon;
        BackColor       = SBG;

        var wa = Screen.FromRectangle(monitorRect).WorkingArea;
        Size = new Size(PANEL_W, wa.Height);

        collapsedLeft = monitorRect.Left - PANEL_W;
        expandedLeft  = monitorRect.Left;
        Location      = new Point(collapsedLeft, wa.Top);

        // Build first so contentPanel ends up behind everything in z-order
        Build();

        // ── left / right borders ──────────────────────────────────────
        Controls.Add(new Panel { Location = new Point(0, 0),                  Size = new Size(BORDER_W, Height), BackColor = SACCT });
        Controls.Add(new Panel { Location = new Point(PANEL_W - BORDER_W, 0), Size = new Size(BORDER_W, Height), BackColor = SACCT });

        // ── bottom border ─────────────────────────────────────────────
        Controls.Add(new Panel { Location = new Point(0, Height - BORDER_W), Size = new Size(PANEL_W, BORDER_W), BackColor = SACCT });

        // ── Quit footer pinned at BOTTOM ─────────────────────────────
        var qFooter = new Panel {
            Location  = new Point(BORDER_W, Height - QUIT_H - BORDER_W),
            Size      = new Size(PANEL_W - BORDER_W * 2, QUIT_H),
            BackColor = SBG,
        };
        qFooter.Controls.Add(new RoundButton("Quit", () => Application.Exit(), PANEL_W - PAD * 2 - BORDER_W * 2, 54, danger: true) {
            Location = new Point(PAD, 8),
            Font = DP.F(14f, FontStyle.Bold),
        });
        Controls.Add(qFooter);
        qFooter.BringToFront();  // Controls[0] — nothing added after this

        int extra = wa.Height - (layoutY + 36) - QUIT_H - BORDER_W * 2;
        if (extra > 0)
        {
            int clipExtra   = Math.Min((int)(extra * 0.25), 28);
            int bottomExtra = Math.Min((int)(extra * 0.12), 14);
            int gapExtra    = extra - clipExtra - bottomExtra;
            int gapPerSep   = sepCount > 0 ? Math.Min(gapExtra / sepCount, 65) : 0;

            foreach (Control c in contentPanel.Controls)
            {
                int shift = 0;
                for (int i = 0; i < sepCount; i++)
                    if (c.Top > sepY[i]) shift += gapPerSep;
                c.Top += shift;
            }

            int clipBottom = clipBtn.Top + clipBtn.Height;
            clipBtn.Height += clipExtra;
            foreach (Control c in contentPanel.Controls)
                if (c != clipBtn && c.Top >= clipBottom)
                    c.Top += clipExtra;

            previewBtn.Height    += bottomExtra;
            editBtn.Height       += bottomExtra;
            openFolderBtn.Height += bottomExtra;
        }

        slideTimer = new System.Windows.Forms.Timer { Interval = 16 };
        slideTimer.Tick += OnSlideTick;
        Load += (_, _) => DwmHelper.Apply(Handle);
    }

    void Build()
    {
        int cpH = Height - QUIT_H - BORDER_W * 2;
        contentPanel = new Panel {
            Location   = new Point(BORDER_W, BORDER_W),
            Size       = new Size(PANEL_W - BORDER_W * 2, cpH),
            BackColor  = SBG,
            AutoScroll = true,
        };
        Controls.Add(contentPanel);

        layoutY = 0;

        // ── accent bar ────────────────────────────────────────────────
        contentPanel.Controls.Add(new Panel {
            Location = Point.Empty, Size = new Size(PANEL_W - BORDER_W * 2, 2), BackColor = SACCT,
        });
        layoutY += 2;

        // ── title bar ─────────────────────────────────────────────────
        var tbar = new Panel { Location = new Point(0, layoutY), Size = new Size(PANEL_W - BORDER_W * 2, 44), BackColor = STBAR };
        // accent left stripe
        tbar.Controls.Add(new Panel { Location = Point.Empty, Size = new Size(3, 44), BackColor = SACCT });
        tbar.Controls.Add(new Label {
            Text = "ATLAS", ForeColor = SFG, Font = DP.F(9f),
            Location = new Point(16, 0), Size = new Size(120, 44),
            TextAlign = ContentAlignment.MiddleLeft, BackColor = STBAR,
        });
        ramLabel  = new Label { Text = "", ForeColor = SFG3, Font = SSF7, AutoSize = true, BackColor = STBAR, Location = new Point(PANEL_W - 200, 14) };
        timeLabel = new Label { Text = "", ForeColor = SFG2, Font = SSF8, AutoSize = true, BackColor = STBAR, Location = new Point(PANEL_W - 110, 14) };
        tbar.Controls.Add(ramLabel);
        tbar.Controls.Add(timeLabel);
        contentPanel.Controls.Add(tbar);
        layoutY += 44;

        AddSep();

        // ── Clip button ── prominent at top ───────────────────────────
        layoutY += 10;
        clipBtnY = layoutY;
        clipBtn = new RoundButton("CLIP", () => owner.TriggerClip(), PANEL_W - PAD * 2, 25, green: true) {
            Location = new Point(PAD, layoutY),
            Font = DP.F(15f, FontStyle.Bold),
        };
        contentPanel.Controls.Add(clipBtn);
        layoutY += 29;

        statusLabel = new Label {
            Text = "Starting…", ForeColor = SFG2, Font = SSF8,
            Location = new Point(PAD, layoutY), Size = new Size(PANEL_W - PAD * 2, 16), BackColor = SBG,
        };
        contentPanel.Controls.Add(statusLabel);

        frameDropLabel = new Label {
            Text = "", ForeColor = Color.FromArgb(0xF0, 0x60, 0x30), Font = SSF7,
            Location = new Point(PANEL_W - PAD - 56, layoutY), Size = new Size(56, 16), BackColor = SBG,
            TextAlign = ContentAlignment.MiddleRight,
        };
        contentPanel.Controls.Add(frameDropLabel);
        layoutY += 20;

        layoutY += 8;

        AddSep();
        AddSecHead("CAPTURE");
        AddDropRow("Monitor",     ref monPicker, owner.GetMonitorLabels());
        AddDropRow("Resolution",  ref resPicker, ["360p", "720p", "1080p"]);
        AddDropRow("FPS",         ref fpsPicker, ["15", "30", "60"]);
        AddDropRow("Output",      ref audPicker, owner.GetAudioDeviceLabels());
        AddDropRow("Input",       ref micPicker, owner.GetMicDeviceLabels());
        AddDropRow("Clip length", ref durPicker, [.. SDurationMap.Keys]);
        AddDropRow("Cursor",     ref curPicker, ["Show", "Hide"]);

        AddSep();
        AddSecHead("OUTPUT");
        AddDropRow("Format",  ref fmtPicker, ["MP4", "MKV"]);
        AddDropRow("Quality", ref crfPicker,  [.. CrfMap.Keys]);

        int hkW = PANEL_W - PAD * 2 - LABEL_W - 8;
        AddRowLbl("Clip hotkey");
        clipHkInput = new HotkeyCapture(owner.Cfg.Hotkey) {
            Location = new Point(PAD + LABEL_W + 8, layoutY - ROW_H + (ROW_H - CTRL_H) / 2),
            Size     = new Size(hkW, CTRL_H),
        };
        clipHkInput.HotkeyChanged += (_, _) => { owner.Cfg.Hotkey = clipHkInput.Hotkey; owner.TriggerRestart(); };
        contentPanel.Controls.Add(clipHkInput);

        AddRowLbl("Sidebar key");
        sbarHkInput = new HotkeyCapture(owner.Cfg.SidebarHotkey) {
            Location = new Point(PAD + LABEL_W + 8, layoutY - ROW_H + (ROW_H - CTRL_H) / 2),
            Size     = new Size(hkW, CTRL_H),
        };
        sbarHkInput.HotkeyChanged += (_, _) => { owner.Cfg.SidebarHotkey = sbarHkInput.Hotkey; owner.RegisterSidebarHotkey(); };
        contentPanel.Controls.Add(sbarHkInput);

        int btnW = 56, ctrlW = PANEL_W - PAD * 2 - LABEL_W - 8;
        AddRowLbl("Save to");
        saveDirInput = new StyledTextBox(owner.Cfg.OutDir) {
            Location = new Point(PAD + LABEL_W + 8, layoutY - ROW_H + (ROW_H - CTRL_H) / 2),
            Size     = new Size(ctrlW - btnW - 6, CTRL_H),
        };
        saveDirInput.Leave   += (_, _) => { owner.Cfg.OutDir = saveDirInput.Text; owner.TriggerRestart(); };
        saveDirInput.KeyDown += (_, ev) => { if (ev.KeyCode == Keys.Return) { owner.Cfg.OutDir = saveDirInput.Text; owner.TriggerRestart(); } };
        contentPanel.Controls.Add(saveDirInput);
        contentPanel.Controls.Add(new RoundButton("Browse", BrowseFolder, btnW, 44) {
            Location = new Point(PAD + LABEL_W + 8 + ctrlW - btnW, layoutY - ROW_H + (ROW_H - 44) / 2),
            Font = DP.F(8f),
        });

        AddSep();
        layoutY += 6;

        int innerW = PANEL_W - PAD * 2;
        int thirdW = innerW / 3;
        previewBtn = new RoundButton("Preview", () => owner.OpenLastClipInternal(), thirdW, 34) {
            Location = new Point(PAD, layoutY), Enabled = false, Font = DP.F(10f, FontStyle.Bold),
        };
        contentPanel.Controls.Add(previewBtn);
        editBtn = new RoundButton("Edit", () => owner.OpenEditorInternal(), thirdW, 34) {
            Location = new Point(PAD + thirdW, layoutY), Enabled = false, Font = DP.F(10f, FontStyle.Bold),
        };
        contentPanel.Controls.Add(editBtn);
        openFolderBtn = new RoundButton("Open folder", () => owner.OpenOutputDirInternal(), innerW - thirdW * 2, 34) {
            Location = new Point(PAD + thirdW * 2, layoutY), Font = DP.F(10f, FontStyle.Bold),
        };
        contentPanel.Controls.Add(openFolderBtn);
        layoutY += 38;



        SyncPickersFromCfg();
    }

    void AddSep()
    {
        if (sepCount < sepY.Length) sepY[sepCount++] = layoutY;
        contentPanel.Controls.Add(new Panel { Location = new Point(0, layoutY), Size = new Size(PANEL_W - BORDER_W * 2, 1), BackColor = SDIV });
        layoutY += 1;
    }

    void AddSecHead(string text)
    {
        layoutY += 10;
        contentPanel.Controls.Add(new SectionLabel {
            Text = text, Font = DP.F(8.5f, FontStyle.Bold),
            Location = new Point(PAD, layoutY),
            Width = PANEL_W - BORDER_W * 2 - PAD,
            BackColor = SBG,
        });
        layoutY += 20;
    }

    void AddRowLbl(string text)
    {
        contentPanel.Controls.Add(new Label {
            Text = text, ForeColor = SFG2, Font = SSF9,
            Location = new Point(PAD, layoutY + (ROW_H - LBL_H) / 2),
            Size = new Size(LABEL_W, LBL_H),
        });
        layoutY += ROW_H;
    }

    void AddDropRow(string label, ref DropPicker picker, string[] opts)
    {
        int ctrlW = PANEL_W - PAD * 2 - LABEL_W - 8;
        AddRowLbl(label);
        var dp = new DropPicker {
            Location = new Point(PAD + LABEL_W + 8, layoutY - ROW_H + (ROW_H - CTRL_H) / 2),
            Size     = new Size(ctrlW, CTRL_H),
        };
        if (opts.Length > 0) dp.SetItems(opts);
        dp.SelectedIndexChanged += (_, _) => ApplyPickersAndRestart();
        contentPanel.Controls.Add(dp);
        picker = dp;
    }

    void SyncPickersFromCfg()
    {
        var cfg = owner.Cfg;
        var mon = owner.Monitors; var aud = owner.AudioDevs; var mic = owner.MicDevs;
        if (mon.Count > 0) monPicker.SelectedIndex = Math.Min(cfg.MonitorIdx, mon.Count - 1);
        resPicker.SelectedItem  = cfg.Res;
        fpsPicker.SelectedItem  = cfg.Fps.ToString();
        audPicker.SelectedIndex = cfg.AudioDevice == null ? 0 : Math.Max(0, aud.IndexOf(cfg.AudioDevice) + 1);
        micPicker.SelectedIndex = cfg.MicDevice   == null ? 0 : Math.Max(0, mic.IndexOf(cfg.MicDevice)   + 1);
        durPicker.SelectedItem  = cfg.ClipLen;
        if (durPicker.SelectedIndex < 0) durPicker.SelectedIndex = 3;
        fmtPicker.SelectedItem  = cfg.Format.ToUpperInvariant();
        if (fmtPicker.SelectedIndex < 0) fmtPicker.SelectedIndex = 0;
        curPicker.SelectedIndex = cfg.ShowCursor ? 0 : 1;
        var crfLabel = CrfMap.FirstOrDefault(kv => kv.Value == cfg.Crf).Key;
        crfPicker.SelectedItem = crfLabel ?? "23 – Default";
        if (crfPicker.SelectedIndex < 0) crfPicker.SelectedIndex = 1;
    }

    void ApplyPickersAndRestart()
    {
        var cfg = owner.Cfg; var aud = owner.AudioDevs; var mic = owner.MicDevs;
        cfg.MonitorIdx  = Math.Max(0, monPicker.SelectedIndex);
        cfg.Res         = resPicker.SelectedItem?.ToString() ?? "1080p";
        cfg.Fps         = int.TryParse(fpsPicker.SelectedItem?.ToString(), out int f) ? f : 30;
        int ai = audPicker.SelectedIndex; cfg.AudioDevice = ai > 0 && ai <= aud.Count ? aud[ai - 1] : null;
        int mi = micPicker.SelectedIndex; cfg.MicDevice   = mi > 0 && mi <= mic.Count ? mic[mi - 1] : null;
        cfg.ClipLen     = durPicker.SelectedItem?.ToString() ?? "30 sec";
        cfg.Format      = fmtPicker.SelectedItem?.ToString()?.ToLower() ?? "mp4";
        cfg.ShowCursor  = curPicker.SelectedIndex != 1;
        string? crfKey  = crfPicker.SelectedItem?.ToString();
        cfg.Crf         = crfKey != null && CrfMap.TryGetValue(crfKey, out int cv) ? cv : 23;
        owner.TriggerRestart();
    }

    void BrowseFolder()
    {
        using var dlg = new FolderBrowserDialog { SelectedPath = saveDirInput.Text };
        if (dlg.ShowDialog() == DialogResult.OK) {
            saveDirInput.Text = dlg.SelectedPath;
            owner.Cfg.OutDir = dlg.SelectedPath;
            owner.TriggerRestart();
        }
    }

    public void Toggle()
    {
        expanded = !expanded;
        slideTimer.Start();
    }

    void OnSlideTick(object? s, EventArgs e)
    {
        int target = expanded ? expandedLeft : collapsedLeft;
        int diff   = target - Left;
        if (Math.Abs(diff) <= 2) { Left = target; slideTimer.Stop(); }
        else Left += diff / 4 + Math.Sign(diff);
    }

    public void UpdateStatus(string time, string status, double elapsed, double cap, string ram = "", int drops = 0, float audioLevel = 0f)
    {
        if (IsDisposed || !IsHandleCreated) return;
        if (InvokeRequired) { BeginInvoke(() => UpdateStatus(time, status, 0, 0, ram, drops)); return; }
        timeLabel.Text   = ram.Length > 0 ? $"{ram}  {time}" : time;
        ramLabel.Text    = "";
        statusLabel.Text = status;
        frameDropLabel.Text = drops > 0 ? $"↓{drops} frm" : "";
    }


    public void SetPreviewEnabled(bool on)
    {
        if (IsDisposed || !IsHandleCreated) return;
        if (InvokeRequired) { BeginInvoke(() => SetPreviewEnabled(on)); return; }
        previewBtn.Enabled = on;
        editBtn.Enabled    = on;
    }

    protected override void OnShown(EventArgs e)
    {
        base.OnShown(e);
        Left = collapsedLeft;
        expanded = false;
        Toggle();  
    }

    protected override CreateParams CreateParams {
        get { var cp = base.CreateParams; cp.ExStyle |= 0x40000; return cp; }  
    }

    protected override void OnFormClosing(FormClosingEventArgs e)
    {
        if (e.CloseReason == CloseReason.UserClosing) { e.Cancel = true; return; }
        slideTimer?.Stop();
        base.OnFormClosing(e);
    }

    protected override void Dispose(bool disposing)
    {
        if (disposing) {
            slideTimer?.Stop(); slideTimer?.Dispose();
        }
        base.Dispose(disposing);
    }
}

