    void AttachDrag(Control ctrl, Control[]? excluded = null)
    {
        if (excluded != null && Array.IndexOf(excluded, ctrl) >= 0) return;
        ctrl.MouseDown += (_, e) => { if (e.Button == MouseButtons.Left) dragStart = Cursor.Position; };
        ctrl.MouseMove += (_, e) => {
            if (e.Button != MouseButtons.Left) return;
            var cur = Cursor.Position;
            Left += cur.X - dragStart.X;
            Top  += cur.Y - dragStart.Y;
            dragStart = cur;
        };
        foreach (Control child in ctrl.Controls) AttachDrag(child, excluded);
    }

    void PopulateAllDropdowns()
    {
        monPicker.ClearItems();
        var monLabels = new string[monitors.Count];
        for (int i = 0; i < monitors.Count; i++) monLabels[i] = monitors[i].ToString();
        monPicker.SetItems(monLabels);
        if (monitors.Count > 0)
            monPicker.SelectedIndex = Math.Min(cfg.MonitorIdx, monitors.Count - 1);

        resPicker.SelectedItem = cfg.Res;
        fpsPicker.SelectedItem = cfg.Fps.ToString();

        audPicker.ClearItems();
        var defDev   = LoopbackRecorder.DefaultOutputDeviceName();
        string defLabel = defDev != null ? $"Default — {defDev}" : "Default";
        audPicker.SetItems(new[] { defLabel }.Concat(audioDevs).ToArray());
        audPicker.SelectedIndex = cfg.AudioDevice == null
            ? 0
            : Math.Max(0, audioDevs.IndexOf(cfg.AudioDevice) + 1);

        micPicker.ClearItems();
        micPicker.SetItems(new[] { "None" }.Concat(micDevs).ToArray());
        micPicker.SelectedIndex = cfg.MicDevice == null
            ? 0
            : Math.Max(0, micDevs.IndexOf(cfg.MicDevice) + 1);

        durPicker.SelectedItem = cfg.ClipLen;
        if (durPicker.SelectedIndex < 0) durPicker.SelectedIndex = 3;

    }

    void ScheduleRestart()
    {
        pendingRestart?.Stop();
        pendingRestart?.Dispose();
        pendingRestart = new System.Windows.Forms.Timer { Interval = 500 };
        pendingRestart.Tick += (s, _) => {
            ((System.Windows.Forms.Timer)s!).Stop();
            SaveAndRestart();
        };
        pendingRestart.Start();
    }

    void SaveAndRestart()
    {
        PersistSettings();
        Shutdown();
        progressBar.SetProgress(0, 1);
        statusLabel.Text = "Restarting capture…";
        var t = new System.Windows.Forms.Timer { Interval = 300 };
        t.Tick += (_, _) => { t.Stop(); t.Dispose(); StartCapture(); };
        t.Start();
    }

    void PersistSettings()
    {
        if (!cfg.SidebarMode)
        {
            cfg.MonitorIdx  = Math.Max(0, monPicker.SelectedIndex);
            cfg.Res         = resPicker.SelectedItem?.ToString() ?? "1080p";
            cfg.Fps         = int.TryParse(fpsPicker.SelectedItem?.ToString(), out int f) ? f : 30;
            int ai          = audPicker.SelectedIndex;
            cfg.AudioDevice = ai > 0 && ai <= audioDevs.Count ? audioDevs[ai - 1] : null;
            int mi          = micPicker.SelectedIndex;
            cfg.MicDevice   = mi > 0 && mi <= micDevs.Count ? micDevs[mi - 1] : null;
            cfg.ClipLen     = durPicker.SelectedItem?.ToString() ?? "30 sec";
            cfg.Hotkey      = hotkeyInput.Hotkey;
            cfg.OutDir      = saveDirInput.Text;
            cfg.Topmost     = alwaysOnTop.Checked;
        }
        cfg.SidebarMode  = true;
        cfg.Persist();
    }

    void StartCapture()
    {
        // Output directory validation
        string outDir = cfg.OutDir;
        try { Directory.CreateDirectory(outDir); }
        catch (Exception ex) {
            statusLabel.Text = $"⚠ Can't create output dir: {ex.Message}";
            sidebar?.UpdateStatus("", statusLabel.Text, 0, 1);
            return;
        }
        string testFile = Path.Combine(outDir, ".atlas_write_test");
        try { File.WriteAllText(testFile, ""); File.Delete(testFile); }
        catch {
            statusLabel.Text = $"⚠ Output dir is read-only: {outDir}";
            sidebar?.UpdateStatus("", statusLabel.Text, 0, 1);
            return;
        }
        // Disk space check
        try {
            var drive = new DriveInfo(Path.GetPathRoot(outDir) ?? "C:\\");
            if (drive.AvailableFreeSpace < 512L * 1024 * 1024)
                statusLabel.Text = $"⚠ Low disk: {drive.AvailableFreeSpace / 1_000_000}MB free";
        } catch { }

        recCts?.Cancel();
        recCts = new CancellationTokenSource();
        var tok = recCts.Token;

        int monIdx  = Math.Max(0, Math.Min(cfg.MonitorIdx, monitors.Count - 1));
        var monitor = monitors.Count > 0 ? monitors[monIdx] : new DisplayInfo(Screen.PrimaryScreen!.Bounds, "Display 1");
        int fps     = cfg.Fps > 0 ? cfg.Fps : 30;
        var outSz   = ScreenGrabber.ScaleToHeight(monitor.Rect, cfg.Res ?? "1080p");
        int bufSecs = (DurationMap.TryGetValue(cfg.ClipLen, out int d) ? d : 30) + 2;

        long maxBytes = (long)(cfg.MaxRamMb > 0 ? cfg.MaxRamMb : 512) * 1024 * 1024;
        vidBuf.SetMaxBytes(maxBytes * 9 / 10);
        audBuf.SetMaxBytes(maxBytes / 20);
        micAudBuf.SetMaxBytes(maxBytes / 20);

        vidBuf.WindowSecs = bufSecs; audBuf.WindowSecs = bufSecs;
        vidBuf.Clear(); audBuf.Clear();
        captureFormat = null;

        string? devName = cfg.AudioDevice;

        audioRec?.Dispose();
        audioRec = new LoopbackRecorder(devName, (data, n) => {
            if (tok.IsCancellationRequested) return;
            audBuf.Add(DateTimeOffset.UtcNow.ToUnixTimeMilliseconds() * 0.001, data);
            if (data.Length >= 4) {
                float sum = 0;
                int count = Math.Min(data.Length / 4, 512);
                for (int i = 0; i < count; i++) {
                    float s = BitConverter.ToSingle(data, i * 4);
                    sum += s * s;
                }
                _audioLevel = Math.Min(1f, (float)Math.Sqrt(sum / count) * 5f);
            }
        });

        bool audioStarted = audioRec.Start();
        if (!audioStarted)
            statusLabel.Text = "Audio device not responding — capturing video only";
        captureFormat = audioRec.CaptureFormat;

        micAudBuf.WindowSecs = bufSecs; micAudBuf.Clear();
        micCaptureFormat = null;
        micAudioRec?.Dispose();
        string? micDev = cfg.MicDevice;
        if (micDev != null)
        {
            micAudioRec = new LoopbackRecorder(micDev, (data, n) => {
                if (tok.IsCancellationRequested) return;
                micAudBuf.Add(DateTimeOffset.UtcNow.ToUnixTimeMilliseconds() * 0.001, data);
            }, captureMode: true);
            micAudioRec.Start();
            micCaptureFormat = micAudioRec.CaptureFormat;
        }
        else
            micAudioRec = null;

        _grabber = new ScreenGrabber(monitor.Rect, outSz, fps,
            (jpg, ts) => vidBuf.Add(ts, jpg), tok, cfg.ShowCursor);
        Task.Run(() => {
            try { _grabber.Run(); }
            catch (Exception ex) when (!tok.IsCancellationRequested)
            { BeginInvoke(() => RecoverFromCrash(ex)); }
        }, tok);

        RegisterHotkeyFromString(cfg.Hotkey);
        RegisterSidebarHotkeyFromString(cfg.SidebarHotkey);
        RegisterAltHotkeyFromString(cfg.HotkeyAlt);
        RegisterMicHotkeyFromString(cfg.MicHotkey);
        _recWatch.Restart();

        if (hotkeyOk)
            statusLabel.Text = $"Buffering  ·  {cfg.Hotkey}  saves the last {cfg.ClipLen}";

        tickTimer.Start();
    }

    void Shutdown()
    {
        tickTimer?.Stop();
        recCts?.Cancel();
        audioRec?.Stop();
        audioRec?.Dispose();
        audioRec = null;
        micAudioRec?.Stop();
        micAudioRec?.Dispose();
        micAudioRec = null;
        UnregisterHotKey(Handle, HK);
        UnregisterHotKey(Handle, HK2);
        UnregisterHotKey(Handle, HK3);
        UnregisterHotKey(Handle, HK4);
    }

