    internal void RegisterSidebarHotkey() => RegisterSidebarHotkeyFromString(cfg.SidebarHotkey);

    void ToggleSidebar(bool on)
    {
        if (on && (sidebar == null || sidebar.IsDisposed))
        {
            Visible = false;
            int monIdx = Math.Max(0, monPicker.SelectedIndex);
            var rect   = monIdx < monitors.Count ? monitors[monIdx].Rect : Screen.PrimaryScreen!.Bounds;
            sidebar    = new SidebarOverlay(this, rect);
            sidebar.Show();
        }
    }

    static bool ParseHotkey(string hk, out uint mods, out uint vk)
    {
        mods = 0; vk = 0;
        if (string.IsNullOrEmpty(hk)) return false;
        foreach (var part in hk.ToLower().Split('+').Select(p => p.Trim()))
        {
            switch (part)
            {
                case "ctrl":  mods |= CTRL;  break;
                case "alt":   mods |= ALT;   break;
                case "shift": mods |= SHIFT; break;
                case "win":   mods |= WIN;   break;
                default:
                    vk = part switch {
                        "space"                => (uint)Keys.Space,
                        "return" or "enter"    => (uint)Keys.Return,
                        "back" or "backspace"  => (uint)Keys.Back,
                        "tab"                  => (uint)Keys.Tab,
                        "escape" or "esc"      => (uint)Keys.Escape,
                        "insert"               => (uint)Keys.Insert,
                        "delete"               => (uint)Keys.Delete,
                        "home"                 => (uint)Keys.Home,
                        "end"                  => (uint)Keys.End,
                        "pgup"                 => (uint)Keys.Prior,
                        "pgdn"                 => (uint)Keys.Next,
                        "up"                   => (uint)Keys.Up,
                        "down"                 => (uint)Keys.Down,
                        "left"                 => (uint)Keys.Left,
                        "right"                => (uint)Keys.Right,
                        _ when part.Length == 1
                            => (uint)char.ToUpper(part[0]),
                        _ when part.StartsWith("f") && int.TryParse(part[1..], out int fn) && fn is >= 1 and <= 24
                            => (uint)(Keys.F1 + fn - 1),
                        _ => 0u
                    };
                    break;
            }
        }
        return vk != 0;
    }

    void RegisterSidebarHotkeyFromString(string hk)
    {
        UnregisterHotKey(Handle, HK2);
        if (ParseHotkey(hk, out uint mods, out uint vk))
            RegisterHotKey(Handle, HK2, mods | NO_REPEAT, vk);
    }

    void RegisterHotkeyFromString(string hk)
    {
        UnregisterHotKey(Handle, HK);
        if (!cfg.HotkeyOn) { hotkeyOk = false; return; }
        if (!ParseHotkey(hk, out uint mods, out uint vk)) {
            statusLabel.Text = $"Couldn't parse hotkey: {hk}";
            return;
        }
        bool ok = RegisterHotKey(Handle, HK, mods | NO_REPEAT, vk);
        if (!ok) statusLabel.Text = $"⚠ {hk} is taken by another app — click Hotkey and press a new combo";
        hotkeyOk = ok;
    }

    void RefreshTimecode()
    {
        if (recCts == null || recCts.IsCancellationRequested) return;
        int cap = DurationMap.TryGetValue(cfg.ClipLen, out int d) ? d : 30;
        double elapsed = Math.Min(_recWatch.Elapsed.TotalSeconds, cap);
        progressBar.SetProgress(elapsed, cap);
        timeLabel.Text = $"{(int)elapsed}s / {cap}s";

        if (elapsed < 2 && statusLabel.Text.StartsWith("Buffering"))
            statusLabel.Text = "Warming up…";
        else if (elapsed >= 2 && statusLabel.Text == "Warming up…")
            statusLabel.Text = $"Buffering  ·  {cfg.Hotkey}  saves the last {cfg.ClipLen}";

        long ramBytes = vidBuf.ApproxBytes + audBuf.ApproxBytes + micAudBuf.ApproxBytes;
        string ram = ramBytes >= 1_000_000 ? (ramBytes / 1_048_576) + "MB" : (ramBytes / 1024) + "KB";
        int drops = _grabber?.DroppedFrames ?? 0;
        sidebar?.UpdateStatus(timeLabel.Text, statusLabel.Text, elapsed, cap, ram, drops, _audioLevel);
    }

    protected override void WndProc(ref Message m)
    {
        if (m.Msg == WM_HOTKEY)
        {
            int id = m.WParam.ToInt32();
            if (id == HK  && cfg.HotkeyOn) { BeginInvoke(_clipAction!); return; }
            if (id == HK2) { BeginInvoke(_sidebarAction!); return; }
            if (id == HK3 && cfg.HotkeyOn) { BeginInvoke(_altClipAction!); return; }
            if (id == HK4) { BeginInvoke(ToggleMic); return; }
            return;
        }
        if (m.Msg == WM_NCHITTEST)
        {
            base.WndProc(ref m);
            if (m.Result.ToInt32() == HTCLIENT)
            {
                var p = PointToClient(Cursor.Position);
                if (p.Y >= 2 && p.Y < 42 && p.X < Width - 76)
                    m.Result = new IntPtr(HTCAPTION);
            }
            return;
        }
        base.WndProc(ref m);
    }

    void TrySaveClip()
    {
        if (saving || ffmpegExe == null) return;
        saving = true;
        Task.Run(PlaySaveChime);

        statusLabel.Text = "Saving clip…";

        int clipSecs = DurationMap.TryGetValue(cfg.ClipLen, out int d) ? d : 30;
        int fps      = cfg.Fps > 0 ? cfg.Fps : 30;
        double from  = (DateTime.UtcNow - DateTime.UnixEpoch).TotalSeconds - clipSecs;

        var frames   = vidBuf.Since(from);
        var audio    = audBuf.Since(from);
        var micAudio = micAudBuf.Since(from);

        var fmt    = captureFormat;
        var micFmt = micCaptureFormat;
        string ff  = ffmpegExe!;
        string dir = cfg.OutDir;

        string clipFmt  = cfg.Format ?? "mp4";
        int    crf      = cfg.Crf;
        string baseName = $"{GameDetector.Detect()}_{DateTime.Now:yyyyMMdd_HHmmss}";
        byte[]? lastJpg = frames.Count > 0 ? frames[^1].payload : null;
        Task.Run(() => ClipEncoder.WriteClip(frames, audio, fmt, micAudio, micFmt, fps, dir, ff, clipFmt, videoEncoder, baseName, crf,
            (ok, info) => BeginInvoke(() => OnSaveComplete(ok, info, frames.Count, lastJpg))));
    }

    void OnSaveComplete(bool success, string info, int frameCount, byte[]? lastJpg)
    {
        saving = false;
        if (success)
        {
            int sp = info.IndexOf(' ');
            string path = sp >= 0 ? info[..sp] : info;
            string meta = sp >= 0 ? info[sp..].Trim() : "";
            lastClipPath = path;
            previewBtn.Enabled = true;
            sidebar?.SetPreviewEnabled(true);

            int drops = audioRec?.LatePackets ?? 0;
            string dropNote = drops > 0 ? $"  ·  {drops} late audio pkts" : "";
            string fileName = Path.GetFileName(path);
            statusLabel.Text = $"Saved {fileName} {meta}{dropNote}";
            trayIcon?.ShowBalloonTip(3000, "Clip saved", $"{fileName} {meta}", ToolTipIcon.None);
        }
        else
        {
            statusLabel.Text = $"Failed: {info[..Math.Min(info.Length, 70)]}";
        }
    }

    void OpenLastClip()
    {
        if (lastClipPath == null || !File.Exists(lastClipPath)) return;
        Process.Start(new ProcessStartInfo(lastClipPath) { UseShellExecute = true });
    }

    void OpenOutputDir()
    {
        try { Directory.CreateDirectory(saveDirInput.Text); } catch { }
        Process.Start(new ProcessStartInfo("explorer", saveDirInput.Text) { UseShellExecute = true });
    }

    void BrowseForFolder()
    {
        using var dlg = new FolderBrowserDialog { SelectedPath = saveDirInput.Text };
        if (dlg.ShowDialog() == DialogResult.OK)
            saveDirInput.Text = dlg.SelectedPath;
    }

    void TrySaveAltClip()
    {
        if (saving || ffmpegExe == null) return;
        int altSecs = DurationMap.TryGetValue(cfg.ClipLenAlt, out int ad) ? ad : 60;
        int fps     = cfg.Fps > 0 ? cfg.Fps : 30;
        double from = (DateTime.UtcNow - DateTime.UnixEpoch).TotalSeconds - altSecs;
        var frames  = vidBuf.Since(from);
        var audio   = audBuf.Since(from);
        var micAudio = micAudBuf.Since(from);
        var fmt = captureFormat; var micFmt = micCaptureFormat;
        string ff = ffmpegExe!; string dir = cfg.OutDir;
        string clipFmt  = cfg.Format ?? "mp4"; int crf = cfg.Crf;
        string baseName = $"{GameDetector.Detect()}_{DateTime.Now:yyyyMMdd_HHmmss}";
        byte[]? lastJpg = frames.Count > 0 ? frames[^1].payload : null;
        saving = true;
        statusLabel.Text = $"Saving {altSecs}s clip…";
        Task.Run(() => ClipEncoder.WriteClip(frames, audio, fmt, micAudio, micFmt, fps, dir, ff, clipFmt, videoEncoder, baseName, crf,
            (ok, info) => BeginInvoke(() => OnSaveComplete(ok, info, frames.Count, lastJpg))));
    }

    void ShowClipToast()
    {
        int monIdx   = Math.Max(0, monPicker.SelectedIndex);
        var monRect  = monIdx < monitors.Count ? monitors[monIdx].Rect : Screen.PrimaryScreen!.Bounds;
        new ClipToast(monRect).ShowToast();
    }

    void ToggleMic()
    {
        _micMuted = !_micMuted;
        if (_micMuted) {
            micAudioRec?.Stop();
            micAudioRec?.Dispose();
            micAudioRec = null;
            statusLabel.Text = "🔇 Mic muted";
        } else if (cfg.MicDevice != null) {
            var tok = recCts?.Token ?? CancellationToken.None;
            micAudBuf.Clear();
            micAudioRec = new LoopbackRecorder(cfg.MicDevice, (data, n) => {
                if (tok.IsCancellationRequested) return;
                micAudBuf.Add(DateTimeOffset.UtcNow.ToUnixTimeMilliseconds() * 0.001, data);
            }, captureMode: true);
            micAudioRec.Start();
            micCaptureFormat = micAudioRec.CaptureFormat;
            statusLabel.Text = "🎙 Mic active";
        }
    }

    void RecoverFromCrash(Exception ex)
    {
        if (recCts?.IsCancellationRequested == true) return;
        statusLabel.Text = "⚠ Capture crashed — restarting…";
        sidebar?.UpdateStatus(timeLabel.Text, statusLabel.Text, 0, 1);
        var t = new System.Windows.Forms.Timer { Interval = 1500 };
        t.Tick += (_, _) => { t.Stop(); t.Dispose(); StartCapture(); };
        t.Start();
    }

    void RegisterAltHotkeyFromString(string hk)
    {
        UnregisterHotKey(Handle, HK3);
        if (!string.IsNullOrWhiteSpace(hk) && ParseHotkey(hk, out uint mods, out uint vk))
            RegisterHotKey(Handle, HK3, mods | NO_REPEAT, vk);
    }

    void RegisterMicHotkeyFromString(string hk)
    {
        UnregisterHotKey(Handle, HK4);
        if (!string.IsNullOrWhiteSpace(hk) && ParseHotkey(hk, out uint mods, out uint vk))
            RegisterHotKey(Handle, HK4, mods | NO_REPEAT, vk);
    }

    void CheckFfmpegVersion(string? ffmpegPath)
    {
        if (ffmpegPath == null) return;
        try {
            var psi = new ProcessStartInfo(ffmpegPath, "-version") {
                UseShellExecute = false, RedirectStandardOutput = true, CreateNoWindow = true
            };
            using var p = Process.Start(psi)!;
            string line = p.StandardOutput.ReadLine() ?? "";
            p.WaitForExit(3000);
            var m = System.Text.RegularExpressions.Regex.Match(line, @"version (\d+)");
            if (m.Success && int.TryParse(m.Groups[1].Value, out int major) && major < 4)
                statusLabel.Text = $"⚠ ffmpeg {major}.x detected — recommend v4+";
        } catch { }
    }

    protected override void OnFormClosed(FormClosedEventArgs e)
    {
        Shutdown();
        sidebar?.Dispose();
        sidebar = null;
        _trayIconHandle?.Dispose();
        _trayIconHandle = null;
        trayIcon?.Dispose();
        trayIcon = null;
        blinkTimer?.Dispose();
        tickTimer?.Dispose();
        pendingRestart?.Dispose();
        base.OnFormClosed(e);
    }

    static void PlaySaveChime()
    {

        var t = new Thread(() =>
        {
            try
            {
                var tmp = Path.Combine(Path.GetTempPath(), "atlas_chime.mp3");
                if (!File.Exists(tmp))
                    File.WriteAllBytes(tmp, Convert.FromBase64String(SoundB64));
                string alias = "ac" + Environment.TickCount64.ToString("X");
                int r1 = mciSendString($"open \"{tmp}\" type mpegvideo alias {alias}", null, 0, IntPtr.Zero);
                int r2 = mciSendString($"play {alias} wait", null, 0, IntPtr.Zero);
                int r3 = mciSendString($"close {alias}", null, 0, IntPtr.Zero);
                if (r1 != 0 || r2 != 0)
                    File.AppendAllText(Program.LogFile, $"[sound] open={r1} play={r2} close={r3} file={tmp}\n");
                try { File.Delete(tmp); } catch { }
            }
            catch (Exception ex) { File.AppendAllText(Program.LogFile, $"[sound ex] {ex.Message}\n"); }
        });
        t.SetApartmentState(ApartmentState.STA);
        t.IsBackground = true;
        t.Start();
    }

